// =============================================================
// مندوبك - Cloudflare Workers + Hono Main Entry
// =============================================================

import { Hono } from 'hono'
import { cors } from 'hono/cors'
import { logger } from 'hono/logger'
import { prettyJSON } from 'hono/pretty-json'
import { ordersRouter } from './routes/orders'
import { couriersRouter } from './routes/couriers'
import { adminRouter } from './routes/admin'
import { pricingRouter } from './routes/pricing'
import { uploadRouter } from './routes/upload'
import { authMiddleware } from './middleware/auth'

export type Env = {
  MANDOUBAK_KV: KVNamespace
  MANDOUBAK_R2: R2Bucket
  SUPABASE_URL: string
  SUPABASE_SERVICE_ROLE_KEY: string
  CLERK_SECRET_KEY: string
  CLERK_WEBHOOK_SECRET: string
  JWT_SECRET: string
  NODE_ENV: string
}

const app = new Hono<{ Bindings: Env }>()

// Middleware
app.use('*', logger())
app.use('*', prettyJSON())
app.use('*', cors({
  origin: ['https://mandoubak.com', 'http://localhost:3000'],
  allowMethods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
}))

// Health check
app.get('/', (c) => c.json({ 
  status: 'ok', 
  app: 'مندوبك API', 
  version: '1.0.0',
  timestamp: new Date().toISOString()
}))

// Public routes
app.route('/api/pricing', pricingRouter)
app.route('/api/upload', uploadRouter)

// Protected routes
app.use('/api/orders/*', authMiddleware)
app.use('/api/couriers/*', authMiddleware)
app.use('/api/admin/*', authMiddleware)

app.route('/api/orders', ordersRouter)
app.route('/api/couriers', couriersRouter)
app.route('/api/admin', adminRouter)

// 404 handler
app.notFound((c) => c.json({ error: 'المسار مش موجود' }, 404))

// Error handler
app.onError((err, c) => {
  console.error('Server error:', err)
  return c.json({ error: 'خطأ في السيرفر', details: err.message }, 500)
})

export default app

// =============================================================
// Auth Middleware - Clerk Token Verification
// =============================================================

import { createMiddleware } from 'hono/factory'
import { createClerkClient } from '@clerk/backend'
import type { Env } from '../index'

export type AuthUser = {
  userId: string
  clerkId: string
  role: 'CLIENT' | 'COURIER' | 'ADMIN'
  phone?: string
}

declare module 'hono' {
  interface ContextVariableMap {
    user: AuthUser
  }
}

export const authMiddleware = createMiddleware<{ Bindings: Env }>(async (c, next) => {
  const authHeader = c.req.header('Authorization')

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'مش مسجل دخول' }, 401)
  }

  const token = authHeader.split(' ')[1]

  try {
    const clerk = createClerkClient({ secretKey: c.env.CLERK_SECRET_KEY })
    const payload = await clerk.verifyToken(token)

    // جيب role اليوزر من Supabase
    const { createClient } = await import('@supabase/supabase-js')
    const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

    const { data: user } = await supabase
      .from('users')
      .select('id, role, phone')
      .eq('clerk_id', payload.sub)
      .single()

    if (!user) {
      return c.json({ error: 'اليوزر مش موجود' }, 401)
    }

    c.set('user', {
      userId: user.id,
      clerkId: payload.sub,
      role: user.role,
      phone: user.phone,
    })

    await next()
  } catch (err) {
    return c.json({ error: 'التوكن مش صحيح' }, 401)
  }
})

export const requireRole = (...roles: AuthUser['role'][]) => 
  createMiddleware<{ Bindings: Env }>(async (c, next) => {
    const user = c.get('user')
    if (!roles.includes(user.role)) {
      return c.json({ error: 'مش عندك صلاحية' }, 403)
    }
    await next()
  })

// =============================================================
// Cloudflare KV Lock - منع Race Condition على الأوردرات
// =============================================================

export type KVLockResult = 
  | { acquired: true; lockKey: string }
  | { acquired: false; reason: string }

const LOCK_TTL_SECONDS = 10  // 10 ثواني timeout للـ lock
const CACHE_TTL_SECONDS = 3  // 3 ثواني cache للأوردرات الجديدة

/**
 * يحاول يحجز lock على أوردر معين
 * بيستخدم KV atomic write عشان يضمن مندوب واحد بس ياخد الأوردر
 */
export async function acquireOrderLock(
  kv: KVNamespace,
  orderId: string,
  courierId: string
): Promise<KVLockResult> {
  const lockKey = `order_lock:${orderId}`

  // محاولة كتابة الـ lock
  // لو فيه value موجود، الـ KV put بياخد المكان
  // بنستخدم خطوتين: GET ثم PUT داخل نفس الـ request

  const existing = await kv.get(lockKey)

  if (existing !== null) {
    return {
      acquired: false,
      reason: `الأوردر محجوز من مندوب تاني (${existing})`
    }
  }

  // ضع الـ lock مع TTL
  await kv.put(lockKey, courierId, { expirationTtl: LOCK_TTL_SECONDS })

  // تحقق إن اللي كتبه هو نفسه (Double-check بعد الكتابة)
  const verify = await kv.get(lockKey)

  if (verify !== courierId) {
    return {
      acquired: false,
      reason: 'مندوب تاني سبقك في نفس اللحظة'
    }
  }

  return { acquired: true, lockKey }
}

/**
 * يفك الـ lock بعد ما الأوردر يتحجز في الـ database
 */
export async function releaseOrderLock(
  kv: KVNamespace,
  orderId: string
): Promise<void> {
  const lockKey = `order_lock:${orderId}`
  await kv.delete(lockKey)
}

/**
 * Cache الأوردرات الجديدة لمدة 3 ثواني
 * عشان 500 مندوب مايضربوش الـ database كل ثانية
 */
export async function cachePendingOrders(
  kv: KVNamespace,
  orders: unknown[]
): Promise<void> {
  const cacheKey = 'pending_orders_cache'
  await kv.put(cacheKey, JSON.stringify({
    data: orders,
    cachedAt: Date.now()
  }), { expirationTtl: CACHE_TTL_SECONDS })
}

/**
 * يجيب الأوردرات من الـ cache
 */
export async function getCachedPendingOrders(
  kv: KVNamespace
): Promise<{ data: unknown[]; cachedAt: number } | null> {
  const cacheKey = 'pending_orders_cache'
  const cached = await kv.get(cacheKey)

  if (!cached) return null

  return JSON.parse(cached)
}

/**
 * يمسح الـ cache بعد قبول أوردر (عشان المناديب يشوفوا التحديث)
 */
export async function invalidatePendingOrdersCache(
  kv: KVNamespace
): Promise<void> {
  await kv.delete('pending_orders_cache')
}

// =============================================================
// Pricing Calculator - حساب سعر التوصيل بـ Haversine Formula
// =============================================================

export type Coordinates = {
  lat: number
  lng: number
}

export type PricingZone = {
  zone: string
  price_per_km: number
  minimum_fee: number
  maximum_fee?: number | null
}

export type DeliveryPriceResult = {
  distanceKm: number
  zone: string
  pricePerKm: number
  minimumFee: number
  calculatedFee: number
  finalFee: number
  breakdown: string
}

/**
 * Haversine Formula - يحسب المسافة بين نقطتين على كرة الأرض
 * النتيجة بالكيلومتر
 */
export function calculateDistance(from: Coordinates, to: Coordinates): number {
  const R = 6371  // نصف قطر الأرض بالكيلومتر

  const dLat = toRadians(to.lat - from.lat)
  const dLng = toRadians(to.lng - from.lng)

  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRadians(from.lat)) * Math.cos(toRadians(to.lat)) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2)

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  const distance = R * c

  return Math.round(distance * 100) / 100  // تقريب لـ 2 decimals
}

function toRadians(degrees: number): number {
  return degrees * (Math.PI / 180)
}

/**
 * يحسب سعر التوصيل بناءً على المسافة ومنطقة التسعير
 */
export function calculateDeliveryFee(
  distanceKm: number,
  pricingZone: PricingZone
): DeliveryPriceResult {
  const calculatedFee = distanceKm * pricingZone.price_per_km

  let finalFee = Math.max(calculatedFee, pricingZone.minimum_fee)

  if (pricingZone.maximum_fee) {
    finalFee = Math.min(finalFee, pricingZone.maximum_fee)
  }

  finalFee = Math.ceil(finalFee)  // تقريب للأعلى لصالح المندوب

  return {
    distanceKm,
    zone: pricingZone.zone,
    pricePerKm: pricingZone.price_per_km,
    minimumFee: pricingZone.minimum_fee,
    calculatedFee: Math.round(calculatedFee * 100) / 100,
    finalFee,
    breakdown: `${distanceKm} كم × ${pricingZone.price_per_km} جنيه = ${calculatedFee.toFixed(2)} جنيه (الحد الأدنى: ${pricingZone.minimum_fee} جنيه)`
  }
}

/**
 * يحدد المنطقة بناءً على الـ coordinates (تقدر تعدل الـ zones حسب مدينتك)
 */
export function detectZone(coords: Coordinates): string {
  // مثال للقاهرة - عدل الـ boundaries حسب مدينتك
  // القاهرة الكبرى
  if (coords.lat >= 29.8 && coords.lat <= 30.2 && 
      coords.lng >= 31.0 && coords.lng <= 31.5) {
    return 'cairo'
  }
  // الجيزة
  if (coords.lat >= 29.9 && coords.lat <= 30.1 && 
      coords.lng >= 30.8 && coords.lng <= 31.1) {
    return 'giza'
  }
  // افتراضي
  return 'default'
}

// =============================================================
// Cloudflare R2 - رفع صور البطايق وعمل Signed URLs
// =============================================================

export type UploadResult = {
  key: string
  url: string
  size: number
}

export type ImageType = 'id_front' | 'id_back' | 'product' | 'ad'

/**
 * رفع صورة على R2
 */
export async function uploadImageToR2(
  bucket: R2Bucket,
  imageBuffer: ArrayBuffer,
  courierId: string,
  imageType: ImageType,
  contentType: string
): Promise<UploadResult> {
  const timestamp = Date.now()
  const extension = contentType.includes('png') ? 'png' : 'jpg'
  const key = `${imageType}/${courierId}/${timestamp}.${extension}`

  await bucket.put(key, imageBuffer, {
    httpMetadata: {
      contentType,
      cacheControl: 'private, no-cache',
    },
    customMetadata: {
      courierId,
      imageType,
      uploadedAt: new Date().toISOString(),
    }
  })

  return {
    key,
    url: key,  // بيتبعت للـ database كـ key مش URL مباشر
    size: imageBuffer.byteLength,
  }
}

/**
 * إنشاء Signed URL صالح لمدة 5 دقايق بس (للأمان)
 * المندوب مايقدرش يشارك الـ link مع حد
 */
export async function createSignedUrl(
  bucket: R2Bucket,
  key: string,
  expiresInSeconds: number = 300  // 5 دقايق
): Promise<string> {
  // R2 مش بيدعم signed URLs مباشرة من الـ Worker
  // بنستخدم حل بديل: نرجع الـ object مباشر من الـ worker
  // أو نستخدم pre-signed URL من AWS S3-compatible API

  // الحل الأكثر أمان: إرجاع لينك مؤقت من خلال endpoint محمي
  const expiresAt = Date.now() + (expiresInSeconds * 1000)
  const tempToken = btoa(`${key}:${expiresAt}`)

  return `/api/media/view?key=${encodeURIComponent(key)}&token=${tempToken}`
}

/**
 * التحقق من صحة الـ signed token
 */
export function verifySignedToken(
  token: string,
  key: string
): { valid: boolean; reason?: string } {
  try {
    const decoded = atob(token)
    const [tokenKey, expiresAtStr] = decoded.split(':')

    if (tokenKey !== key) {
      return { valid: false, reason: 'التوكن مش صحيح' }
    }

    const expiresAt = parseInt(expiresAtStr)
    if (Date.now() > expiresAt) {
      return { valid: false, reason: 'اللينك انتهت صلاحيته' }
    }

    return { valid: true }
  } catch {
    return { valid: false, reason: 'توكن غلط' }
  }
}

/**
 * حذف صورة من R2
 */
export async function deleteImageFromR2(
  bucket: R2Bucket,
  key: string
): Promise<void> {
  await bucket.delete(key)
}

/**
 * التحقق من حجم وامتداد الصورة قبل الرفع
 */
export function validateImage(
  size: number,
  contentType: string
): { valid: boolean; error?: string } {
  const MAX_SIZE = 5 * 1024 * 1024  // 5MB
  const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp']

  if (size > MAX_SIZE) {
    return { valid: false, error: 'حجم الصورة أكبر من 5MB' }
  }

  if (!ALLOWED_TYPES.includes(contentType)) {
    return { valid: false, error: 'نوع الملف غير مدعوم (JPG, PNG, WebP فقط)' }
  }

  return { valid: true }
}

// =============================================================
// Orders API - POST /orders, GET /orders/pending, POST /orders/:id/accept
// =============================================================

import { Hono } from 'hono'
import { z } from 'zod'
import { zValidator } from '@hono/zod-validator'
import { createClient } from '@supabase/supabase-js'
import type { Env } from '../index'
import { requireRole } from '../middleware/auth'
import {
  acquireOrderLock,
  releaseOrderLock,
  cachePendingOrders,
  getCachedPendingOrders,
  invalidatePendingOrdersCache,
} from '../lib/kv-lock'
import { calculateDistance, calculateDeliveryFee, detectZone } from '../lib/pricing'

export const ordersRouter = new Hono<{ Bindings: Env }>()

// =====================
// Schema Validation
// =====================
const createOrderSchema = z.object({
  type: z.enum(['SHOPPING', 'DELIVERY']),
  pickupLat: z.number(),
  pickupLng: z.number(),
  deliveryLat: z.number(),
  deliveryLng: z.number(),
  pickupDetails: z.string().optional(),
  deliveryDetails: z.string().optional(),
  notes: z.string().optional(),
  items: z.array(z.object({
    name: z.string(),
    description: z.string().optional(),
    quantity: z.number().default(1),
    price: z.number().optional(),
    shopName: z.string().optional(),
    shopAddress: z.string().optional(),
  })).optional(),
  adOfferId: z.string().optional(),
})

// =====================
// POST /orders - إنشاء أوردر جديد
// =====================
ordersRouter.post('/', async (c) => {
  const user = c.get('user')
  const body = await c.req.json()

  const parsed = createOrderSchema.safeParse(body)
  if (!parsed.success) {
    return c.json({ error: 'بيانات غلط', details: parsed.error.flatten() }, 400)
  }

  const { type, pickupLat, pickupLng, deliveryLat, deliveryLng,
    pickupDetails, deliveryDetails, notes, items, adOfferId } = parsed.data

  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  // حساب المسافة وسعر التوصيل
  const distanceKm = calculateDistance(
    { lat: pickupLat, lng: pickupLng },
    { lat: deliveryLat, lng: deliveryLng }
  )

  const zone = detectZone({ lat: pickupLat, lng: pickupLng })

  const { data: pricing } = await supabase
    .from('admin_pricing')
    .select('*')
    .eq('zone', zone)
    .eq('is_active', true)
    .single()

  if (!pricing) {
    return c.json({ error: 'منطقة التوصيل مش متاحة دلوقتي' }, 400)
  }

  const priceResult = calculateDeliveryFee(distanceKm, pricing)

  // إنشاء رقم أوردر فريد
  const orderNumber = `ORD-${Date.now()}-${Math.random().toString(36).substr(2, 4).toUpperCase()}`

  // إنشاء الأوردر في الـ database
  const { data: order, error: orderError } = await supabase
    .from('orders')
    .insert({
      order_number: orderNumber,
      client_id: user.userId,
      type,
      status: 'PENDING',
      pickup_lat: pickupLat,
      pickup_lng: pickupLng,
      delivery_lat: deliveryLat,
      delivery_lng: deliveryLng,
      pickup_details: pickupDetails,
      delivery_details: deliveryDetails,
      distance_km: distanceKm,
      delivery_fee: priceResult.finalFee,
      notes,
      ad_offer_id: adOfferId || null,
    })
    .select()
    .single()

  if (orderError) {
    console.error('Order creation error:', orderError)
    return c.json({ error: 'مقدرناش ننشئ الأوردر' }, 500)
  }

  // إضافة الـ items لو موجودة
  if (items && items.length > 0) {
    await supabase.from('order_items').insert(
      items.map(item => ({
        order_id: order.id,
        name: item.name,
        description: item.description,
        quantity: item.quantity,
        price: item.price,
        shop_name: item.shopName,
        shop_address: item.shopAddress,
      }))
    )
  }

  // مسح الـ cache عشان المناديب يشوفوا الأوردر الجديد فوراً
  await invalidatePendingOrdersCache(c.env.MANDOUBAK_KV)

  return c.json({
    success: true,
    order: {
      ...order,
      deliveryFee: priceResult.finalFee,
      distanceKm,
      priceBreakdown: priceResult.breakdown,
    }
  }, 201)
})

// =====================
// GET /orders/pending - الأوردرات المنتظرة (للمناديب)
// =====================
ordersRouter.get('/pending', requireRole('COURIER', 'ADMIN'), async (c) => {
  // الأول جرب الـ Cache (3 ثواني)
  const cached = await getCachedPendingOrders(c.env.MANDOUBAK_KV)
  if (cached) {
    return c.json({
      success: true,
      orders: cached.data,
      fromCache: true,
      cachedAt: new Date(cached.cachedAt).toISOString()
    })
  }

  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const { data: orders, error } = await supabase
    .from('orders')
    .select(`
      id, order_number, type, status,
      pickup_lat, pickup_lng, delivery_lat, delivery_lng,
      pickup_details, delivery_details,
      distance_km, delivery_fee, notes,
      created_at,
      order_items (name, quantity, shop_name, shop_address),
      ad_offers (title, shop_name, product_name)
    `)
    .eq('status', 'PENDING')
    .order('created_at', { ascending: false })
    .limit(50)

  if (error) {
    return c.json({ error: 'مقدرناش نجيب الأوردرات' }, 500)
  }

  // Cache النتايج لمدة 3 ثواني
  await cachePendingOrders(c.env.MANDOUBAK_KV, orders || [])

  return c.json({
    success: true,
    orders: orders || [],
    fromCache: false,
    fetchedAt: new Date().toISOString()
  })
})

// =====================
// POST /orders/:id/accept - قبول أوردر (منع Race Condition)
// =====================
ordersRouter.post('/:id/accept', requireRole('COURIER'), async (c) => {
  const user = c.get('user')
  const orderId = c.req.param('id')

  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  // جيب الـ courier_id من الـ database
  const { data: courier } = await supabase
    .from('couriers')
    .select('id, status')
    .eq('user_id', user.userId)
    .single()

  if (!courier) {
    return c.json({ error: 'بروفايل المندوب مش موجود' }, 400)
  }

  if (courier.status !== 'APPROVED') {
    return c.json({ error: 'حسابك لسه تحت المراجعة' }, 403)
  }

  // Step 1: KV Lock (منع السباق على مستوى الـ Edge)
  const lockResult = await acquireOrderLock(c.env.MANDOUBAK_KV, orderId, courier.id)

  if (!lockResult.acquired) {
    return c.json({
      success: false,
      error: 'الأوردر اتحجز',
      message: lockResult.reason
    }, 409)
  }

  try {
    // Step 2: Atomic Transaction في Supabase (منع السباق على مستوى الـ DB)
    const { data: result, error } = await supabase
      .rpc('accept_order', {
        p_order_id: orderId,
        p_courier_id: courier.id
      })

    if (error) {
      await releaseOrderLock(c.env.MANDOUBAK_KV, orderId)
      return c.json({ error: 'خطأ في قبول الأوردر' }, 500)
    }

    if (!result.success) {
      await releaseOrderLock(c.env.MANDOUBAK_KV, orderId)
      return c.json({
        success: false,
        error: result.message
      }, 409)
    }

    // Step 3: مسح الـ Cache فوراً عشان الأوردر يختفي من المناديب
    await invalidatePendingOrdersCache(c.env.MANDOUBAK_KV)

    // Step 4: فك الـ lock بعد ما التحديث اتعمل
    await releaseOrderLock(c.env.MANDOUBAK_KV, orderId)

    return c.json({
      success: true,
      message: 'تم قبول الأوردر بنجاح!',
      orderId,
    })

  } catch (err) {
    await releaseOrderLock(c.env.MANDOUBAK_KV, orderId)
    return c.json({ error: 'خطأ غير متوقع' }, 500)
  }
})

// =====================
// GET /orders/my - أوردرات اليوزر الحالي
// =====================
ordersRouter.get('/my', async (c) => {
  const user = c.get('user')
  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const query = user.role === 'COURIER'
    ? supabase.from('orders').select(`
        *, order_items(*), ad_offers(title, shop_name)
      `).eq('courier_id', (await supabase.from('couriers').select('id').eq('user_id', user.userId).single()).data?.id)
    : supabase.from('orders').select(`
        *, order_items(*), ad_offers(title, shop_name), couriers(name, phone, rating)
      `).eq('client_id', user.userId)

  const { data: orders, error } = await query
    .order('created_at', { ascending: false })
    .limit(20)

  if (error) {
    return c.json({ error: 'مقدرناش نجيب الأوردرات' }, 500)
  }

  return c.json({ success: true, orders: orders || [] })
})

// =====================
// PATCH /orders/:id/status - تحديث حالة الأوردر
// =====================
ordersRouter.patch('/:id/status', requireRole('COURIER', 'ADMIN'), async (c) => {
  const user = c.get('user')
  const orderId = c.req.param('id')
  const { status } = await c.req.json()

  const validStatuses = ['PICKED_UP', 'DELIVERED', 'CANCELLED']
  if (!validStatuses.includes(status)) {
    return c.json({ error: 'حالة غير صحيحة' }, 400)
  }

  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const updates: Record<string, unknown> = { status, updated_at: new Date().toISOString() }
  if (status === 'DELIVERED') updates.completed_at = new Date().toISOString()
  if (status === 'CANCELLED') updates.cancelled_at = new Date().toISOString()

  const { error } = await supabase
    .from('orders')
    .update(updates)
    .eq('id', orderId)

  if (error) {
    return c.json({ error: 'مقدرناش نحدث الحالة' }, 500)
  }

  return c.json({ success: true, message: 'تم تحديث الحالة' })
})

// =============================================================
// Couriers API - تسجيل وإدارة المناديب
// =============================================================

import { Hono } from 'hono'
import { z } from 'zod'
import { createClient } from '@supabase/supabase-js'
import type { Env } from '../index'
import { requireRole } from '../middleware/auth'

export const couriersRouter = new Hono<{ Bindings: Env }>()

// =====================
// POST /couriers/register - تسجيل مندوب جديد
// =====================
couriersRouter.post('/register', async (c) => {
  const user = c.get('user')
  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const body = await c.req.json()

  const schema = z.object({
    name: z.string().min(3),
    phone: z.string().regex(/^01[0-9]{9}$/, 'رقم موبايل مصري غير صحيح'),
    address: z.string().min(10),
    idFrontKey: z.string(),  // مفتاح صورة R2
    idBackKey: z.string(),   // مفتاح صورة R2
  })

  const parsed = schema.safeParse(body)
  if (!parsed.success) {
    return c.json({ error: 'بيانات غير صحيحة', details: parsed.error.flatten() }, 400)
  }

  const { name, phone, address, idFrontKey, idBackKey } = parsed.data

  // التحقق إن رقم الموبايل مش موجود (منع التكرار)
  const { data: existing } = await supabase
    .from('couriers')
    .select('id, phone')
    .eq('phone', phone)
    .single()

  if (existing) {
    return c.json({ 
      error: 'رقم الموبايل ده مسجل بالفعل',
      message: 'كل مندوب له رقم موبايل واحد بس' 
    }, 409)
  }

  // التحقق إن المندوب مش مسجل بالفعل
  const { data: existingCourier } = await supabase
    .from('couriers')
    .select('id')
    .eq('user_id', user.userId)
    .single()

  if (existingCourier) {
    return c.json({ error: 'انت مسجل كمندوب بالفعل' }, 409)
  }

  // تحديث role في جدول users
  await supabase
    .from('users')
    .update({ role: 'COURIER', phone })
    .eq('id', user.userId)

  // إنشاء بروفايل المندوب
  const { data: courier, error } = await supabase
    .from('couriers')
    .insert({
      user_id: user.userId,
      name,
      phone,
      address,
      id_front_image_url: idFrontKey,
      id_back_image_url: idBackKey,
      status: 'PENDING_REVIEW',
    })
    .select()
    .single()

  if (error) {
    if (error.code === '23505') {
      return c.json({ error: 'رقم الموبايل مكرر' }, 409)
    }
    console.error('Courier registration error:', error)
    return c.json({ error: 'مقدرناش نسجل بياناتك' }, 500)
  }

  return c.json({
    success: true,
    message: 'تم التسجيل! بياناتك تحت المراجعة، هنتواصل معاك خلال 24 ساعة.',
    courier: {
      id: courier.id,
      name: courier.name,
      status: courier.status,
    }
  }, 201)
})

// =====================
// GET /couriers/profile - بروفايل المندوب
// =====================
couriersRouter.get('/profile', requireRole('COURIER'), async (c) => {
  const user = c.get('user')
  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  const { data: courier, error } = await supabase
    .from('couriers')
    .select(`
      id, name, phone, address, status, rating, 
      total_deliveries, is_online, created_at,
      courier_ratings(rating, comment, created_at)
    `)
    .eq('user_id', user.userId)
    .single()

  if (error || !courier) {
    return c.json({ error: 'بروفايل مش موجود' }, 404)
  }

  // حساب متوسط التقييم
  const ratings = (courier.courier_ratings as { rating: number }[]) || []
  const avgRating = ratings.length > 0
    ? ratings.reduce((sum, r) => sum + r.rating, 0) / ratings.length
    : 0

  return c.json({
    success: true,
    courier: {
      ...courier,
      averageRating: Math.round(avgRating * 10) / 10,
      totalRatings: ratings.length,
    }
  })
})

