import { useState, useEffect } from 'react'
import { useAuth } from '@clerk/clerk-react'
import toast from 'react-hot-toast'
import { 
  MapPin, Package, ShoppingBag, Truck, 
  Plus, Minus, Calculator, CheckCircle, ArrowLeft
} from 'lucide-react'

type OrderType = 'SHOPPING' | 'DELIVERY'
type Step = 'type' | 'details' | 'confirm' | 'success'

interface OrderItem {
  name: string
  quantity: number
  shopName: string
  shopAddress: string
}

interface PriceEstimate {
  distanceKm: number
  deliveryFee: number
  breakdown: string
}

export default function OrderPage() {
  const { getToken } = useAuth()
  const [step, setStep] = useState<Step>('type')
  const [orderType, setOrderType] = useState<OrderType>('SHOPPING')
  const [items, setItems] = useState<OrderItem[]>([
    { name: '', quantity: 1, shopName: '', shopAddress: '' }
  ])
  const [pickupDetails, setPickupDetails] = useState('')
  const [deliveryDetails, setDeliveryDetails] = useState('')
  const [notes, setNotes] = useState('')
  const [priceEstimate, setPriceEstimate] = useState<PriceEstimate | null>(null)
  const [loadingPrice, setLoadingPrice] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [createdOrder, setCreatedOrder] = useState<{ orderNumber: string; deliveryFee: number } | null>(null)

  // مواقع افتراضية للعرض (في التطبيق الحقيقي يجيوا من GPS / Google Maps)
  const DEMO_PICKUP = { lat: 30.0444, lng: 31.2357 }
  const DEMO_DELIVERY = { lat: 30.0574, lng: 31.2228 }

  async function calculatePrice() {
    setLoadingPrice(true)
    try {
      const params = new URLSearchParams({
        pickupLat: DEMO_PICKUP.lat.toString(),
        pickupLng: DEMO_PICKUP.lng.toString(),
        deliveryLat: DEMO_DELIVERY.lat.toString(),
        deliveryLng: DEMO_DELIVERY.lng.toString(),
      })
      const res = await fetch(`/api/pricing/calculate?${params}`)
      if (res.ok) {
        const data = await res.json()
        setPriceEstimate({
          distanceKm: data.estimate.distanceKm,
          deliveryFee: data.estimate.deliveryFee,
          breakdown: data.estimate.breakdown,
        })
      } else {
        // Demo price when API not connected
        setPriceEstimate({
          distanceKm: 2.3,
          deliveryFee: 25,
          breakdown: '2.3 كم × 8 جنيه = 18.4 جنيه (الحد الأدنى: 25 جنيه)',
        })
      }
    } catch {
      // Demo fallback
      setPriceEstimate({
        distanceKm: 2.3,
        deliveryFee: 25,
        breakdown: '2.3 كم × 8 جنيه = 18.4 جنيه (الحد الأدنى: 25 جنيه)',
      })
    } finally {
      setLoadingPrice(false)
    }
  }

  async function submitOrder() {
    setSubmitting(true)
    try {
      const token = await getToken()
      const body = {
        type: orderType,
        pickupLat: DEMO_PICKUP.lat,
        pickupLng: DEMO_PICKUP.lng,
        deliveryLat: DEMO_DELIVERY.lat,
        deliveryLng: DEMO_DELIVERY.lng,
        pickupDetails,
        deliveryDetails,
        notes,
        items: orderType === 'SHOPPING' ? items.filter(i => i.name) : undefined,
      }

      const res = await fetch('/api/orders', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(body),
      })

      if (res.ok) {
        const data = await res.json()
        setCreatedOrder({
          orderNumber: data.order.order_number,
          deliveryFee: data.order.deliveryFee,
        })
        setStep('success')
        toast.success('🎉 تم تسجيل طلبك بنجاح!')
      } else {
        const data = await res.json()
        toast.error(data.error || 'مقدرناش نسجل طلبك')
      }
    } catch {
      toast.error('في مشكلة في الاتصال، جرب تاني')
    } finally {
      setSubmitting(false)
    }
  }

  const addItem = () => setItems([...items, { name: '', quantity: 1, shopName: '', shopAddress: '' }])
  const removeItem = (i: number) => setItems(items.filter((_, idx) => idx !== i))
  const updateItem = (i: number, field: keyof OrderItem, value: string | number) => {
    setItems(items.map((item, idx) => idx === i ? { ...item, [field]: value } : item))
  }

  const canProceed = () => {
    if (step === 'details') {
      if (orderType === 'SHOPPING') return items.some(i => i.name.trim())
      return pickupDetails.trim() && deliveryDetails.trim()
    }
    return true
  }

  // Success Screen
  if (step === 'success' && createdOrder) {
    return (
      <div className="max-w-md mx-auto text-center py-12">
        <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle className="text-green-500" size={48} />
        </div>
        <h1 className="text-2xl font-black mb-2">تم تسجيل طلبك! 🎉</h1>
        <p className="text-gray-500 mb-2">رقم الطلب: <span className="font-bold text-gray-900">{createdOrder.orderNumber}</span></p>
        <p className="text-gray-500 mb-8">سعر التوصيل: <span className="font-bold text-orange-600">{createdOrder.deliveryFee} جنيه</span></p>
        <div className="card mb-6 text-right">
          <h3 className="font-bold mb-3">🛵 جاري البحث عن مندوب...</h3>
          <div className="space-y-2 text-sm text-gray-600">
            <p>✅ طلبك ظهر لكل المناديب المتاحين</p>
            <p>⏱️ أول مندوب يقبل هياخد طلبك فوراً</p>
            <p>📱 هتجيلك إشعار لما المندوب يقبل</p>
          </div>
        </div>
        <button
          onClick={() => {
            setStep('type')
            setItems([{ name: '', quantity: 1, shopName: '', shopAddress: '' }])
            setPickupDetails('')
            setDeliveryDetails('')
            setPriceEstimate(null)
            setCreatedOrder(null)
          }}
          className="btn-primary w-full"
        >
          طلب جديد
        </button>
      </div>
    )
  }

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      {/* Progress */}
      <div className="flex items-center gap-2">
        {(['type', 'details', 'confirm'] as Step[]).map((s, i) => (
          <div key={s} className="flex items-center gap-2 flex-1">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
              step === s ? 'bg-orange-500 text-white' :
              ['type', 'details', 'confirm'].indexOf(step) > i ? 'bg-green-500 text-white' :
              'bg-gray-200 text-gray-500'
            }`}>
              {['type', 'details', 'confirm'].indexOf(step) > i ? '✓' : i + 1}
            </div>
            {i < 2 && <div className={`flex-1 h-1 rounded-full ${['type', 'details', 'confirm'].indexOf(step) > i ? 'bg-green-400' : 'bg-gray-200'}`} />}
          </div>
        ))}
      </div>

      {/* Step 1: Type Selection */}
      {step === 'type' && (
        <div className="space-y-4 animate-fade-in">
          <h1 className="text-2xl font-black">نوع الطلب</h1>
          <p className="text-gray-500">اختار نوع الطلب اللي عايزه</p>
          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => { setOrderType('SHOPPING'); setStep('details') }}
              className={`card p-6 text-center border-2 transition-all hover:border-orange-400 ${orderType === 'SHOPPING' ? 'border-orange-500 bg-orange-50' : 'border-transparent'}`}
            >
              <ShoppingBag className="mx-auto mb-3 text-orange-500" size={40} />
              <h3 className="font-bold text-lg">مشتريات</h3>
              <p className="text-sm text-gray-500 mt-1">اشتري من محل أو مطعم</p>
            </button>
            <button
              onClick={() => { setOrderType('DELIVERY'); setStep('details') }}
              className={`card p-6 text-center border-2 transition-all hover:border-orange-400 ${orderType === 'DELIVERY' ? 'border-orange-500 bg-orange-50' : 'border-transparent'}`}
            >
              <Truck className="mx-auto mb-3 text-orange-500" size={40} />
              <h3 className="font-bold text-lg">توصيل</h3>
              <p className="text-sm text-gray-500 mt-1">وصّل حاجة من A لـ B</p>
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Details */}
      {step === 'details' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('type')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">
              {orderType === 'SHOPPING' ? '🛒 تفاصيل المشتريات' : '🚚 تفاصيل التوصيل'}
            </h1>
          </div>

          {orderType === 'SHOPPING' ? (
            <div className="space-y-4">
              <h3 className="font-bold text-gray-700">المنتجات المطلوبة</h3>
              {items.map((item, i) => (
                <div key={i} className="card space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="font-semibold text-sm text-gray-600">منتج {i + 1}</span>
                    {items.length > 1 && (
                      <button onClick={() => removeItem(i)} className="text-red-400 hover:text-red-600">
                        <Minus size={18} />
                      </button>
                    )}
                  </div>
                  <input
                    className="input"
                    placeholder="اسم المنتج *"
                    value={item.name}
                    onChange={e => updateItem(i, 'name', e.target.value)}
                  />
                  <div className="grid grid-cols-2 gap-3">
                    <input
                      className="input"
                      placeholder="اسم المحل"
                      value={item.shopName}
                      onChange={e => updateItem(i, 'shopName', e.target.value)}
                    />
                    <div className="flex items-center gap-2">
                      <label className="text-sm text-gray-600 whitespace-nowrap">الكمية:</label>
                      <div className="flex items-center gap-2">
                        <button onClick={() => updateItem(i, 'quantity', Math.max(1, item.quantity - 1))}
                          className="w-8 h-8 rounded-lg bg-gray-100 hover:bg-gray-200 flex items-center justify-center">
                          <Minus size={14} />
                        </button>
                        <span className="w-8 text-center font-bold">{item.quantity}</span>
                        <button onClick={() => updateItem(i, 'quantity', item.quantity + 1)}
                          className="w-8 h-8 rounded-lg bg-orange-100 hover:bg-orange-200 text-orange-600 flex items-center justify-center">
                          <Plus size={14} />
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
              <button onClick={addItem} className="btn-secondary w-full flex items-center justify-center gap-2">
                <Plus size={18} />
                إضافة منتج
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="card space-y-3">
                <div className="flex items-center gap-2 text-orange-600 font-bold">
                  <MapPin size={18} />
                  نقطة الاستلام (A)
                </div>
                <input
                  className="input"
                  placeholder="العنوان الكامل لنقطة الاستلام *"
                  value={pickupDetails}
                  onChange={e => setPickupDetails(e.target.value)}
                />
              </div>
              <div className="card space-y-3">
                <div className="flex items-center gap-2 text-green-600 font-bold">
                  <MapPin size={18} />
                  نقطة التوصيل (B)
                </div>
                <input
                  className="input"
                  placeholder="العنوان الكامل لنقطة التوصيل *"
                  value={deliveryDetails}
                  onChange={e => setDeliveryDetails(e.target.value)}
                />
              </div>
            </div>
          )}

          <div>
            <label className="block text-sm font-semibold text-gray-600 mb-2">ملاحظات (اختياري)</label>
            <textarea
              className="input resize-none h-20"
              placeholder="أي تعليمات خاصة للمندوب..."
              value={notes}
              onChange={e => setNotes(e.target.value)}
            />
          </div>

          <button
            disabled={!canProceed()}
            onClick={() => { calculatePrice(); setStep('confirm') }}
            className="btn-primary w-full flex items-center justify-center gap-2"
          >
            <Calculator size={20} />
            احسب السعر وكمّل
          </button>
        </div>
      )}

      {/* Step 3: Confirm */}
      {step === 'confirm' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('details')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">تأكيد الطلب</h1>
          </div>

          {/* Price Card */}
          <div className="bg-orange-50 border-2 border-orange-200 rounded-2xl p-5">
            <h3 className="font-bold text-orange-700 mb-3 flex items-center gap-2">
              <Calculator size={20} />
              سعر التوصيل
            </h3>
            {loadingPrice ? (
              <div className="flex items-center gap-2 text-orange-600">
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-orange-500 border-t-transparent" />
                جاري الحساب...
              </div>
            ) : priceEstimate ? (
              <div>
                <div className="text-3xl font-black text-orange-600 mb-1">
                  {priceEstimate.deliveryFee} جنيه
                </div>
                <div className="text-sm text-orange-700 opacity-80">{priceEstimate.breakdown}</div>
                <div className="text-xs text-orange-500 mt-1">📍 المسافة: {priceEstimate.distanceKm} كم</div>
              </div>
            ) : (
              <div className="text-red-500 text-sm">مقدرناش نحسب السعر، هيتحدد بعد التأكيد</div>
            )}
          </div>

          {/* Order Summary */}
          <div className="card">
            <h3 className="font-bold mb-3">ملخص الطلب</h3>
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-gray-500">النوع</span>
                <span className="font-semibold">{orderType === 'SHOPPING' ? '🛒 مشتريات' : '🚚 توصيل'}</span>
              </div>
              {orderType === 'SHOPPING' && items.filter(i => i.name).map((item, i) => (
                <div key={i} className="flex justify-between">
                  <span className="text-gray-500">{item.name}</span>
                  <span className="font-semibold">× {item.quantity}</span>
                </div>
              ))}
              {orderType === 'DELIVERY' && (
                <>
                  <div className="flex justify-between">
                    <span className="text-gray-500">من</span>
                    <span className="font-semibold text-left max-w-[60%]">{pickupDetails}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-500">إلى</span>
                    <span className="font-semibold text-left max-w-[60%]">{deliveryDetails}</span>
                  </div>
                </>
              )}
              {notes && (
                <div className="flex justify-between">
                  <span className="text-gray-500">ملاحظات</span>
                  <span className="font-semibold">{notes}</span>
                </div>
              )}
            </div>
          </div>

          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <strong>⚠️ ملاحظة:</strong> العميل بيدفع تمن التوصيل بس. تمن المشتريات بيتسلم للمندوب مباشرة.
          </div>

          <button
            disabled={submitting}
            onClick={submitOrder}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg"
          >
            {submitting ? (
              <>
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />
                جاري التسجيل...
              </>
            ) : (
              <>
                <Package size={22} />
                تأكيد الطلب
              </>
            )}
          </button>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import { useAuth, useUser } from '@clerk/clerk-react'
import toast from 'react-hot-toast'
import { 
  Truck, Package, Clock, MapPin, CheckCircle, 
  Wifi, WifiOff, RefreshCw, ShoppingBag, Bell
} from 'lucide-react'
import { subscribeToOrders } from '../../lib/supabase-realtime'
import type { Order } from '../../lib/api'

const STATUS_COLORS: Record<string, string> = {
  PENDING: 'badge-pending',
  ACCEPTED: 'badge-accepted',
  PICKED_UP: 'badge-accepted',
  DELIVERED: 'badge-delivered',
  CANCELLED: 'badge-cancelled',
}

const STATUS_LABELS: Record<string, string> = {
  PENDING: 'منتظر',
  ACCEPTED: 'مقبول',
  PICKED_UP: 'تم الاستلام',
  DELIVERED: 'تم التوصيل',
  CANCELLED: 'ملغي',
}

export default function CourierDashboard() {
  const { getToken } = useAuth()
  const { user } = useUser()
  const [pendingOrders, setPendingOrders] = useState<Order[]>([])
  const [myOrders, setMyOrders] = useState<Order[]>([])
  const [loading, setLoading] = useState(true)
  const [accepting, setAccepting] = useState<string | null>(null)
  const [isOnline, setIsOnline] = useState(true)
  const [isConnected, setIsConnected] = useState(false)
  const [lastRefresh, setLastRefresh] = useState<Date>(new Date())
  const [tab, setTab] = useState<'pending' | 'mine'>('pending')

  const loadPendingOrders = useCallback(async () => {
    try {
      const token = await getToken()
      const res = await fetch('/api/orders/pending', {
        headers: { Authorization: `Bearer ${token}` }
      })
      if (res.ok) {
        const data = await res.json()
        setPendingOrders(data.orders || [])
        setLastRefresh(new Date())
      }
    } catch {
      // API might not be connected - use demo data
      setPendingOrders(DEMO_PENDING_ORDERS)
    } finally {
      setLoading(false)
    }
  }, [getToken])

  const loadMyOrders = useCallback(async () => {
    try {
      const token = await getToken()
      const res = await fetch('/api/orders/my', {
        headers: { Authorization: `Bearer ${token}` }
      })
      if (res.ok) {
        const data = await res.json()
        setMyOrders(data.orders || [])
      }
    } catch {
      setMyOrders(DEMO_MY_ORDERS)
    }
  }, [getToken])

  useEffect(() => {
    loadPendingOrders()
    loadMyOrders()

    // Supabase Realtime subscription
    const unsubscribe = subscribeToOrders((event) => {
      setIsConnected(true)
      if (event.type === 'INSERT') {
        setPendingOrders(prev => [event.order, ...prev])
        toast('🆕 طلب جديد وصل!', { icon: '📦', duration: 3000 })
        // إشعار صوتي
        try {
          new Audio('data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAA...').play().catch(() => {})
        } catch { /* ignore */ }
      } else if (event.type === 'UPDATE' && event.order.status !== 'PENDING') {
        setPendingOrders(prev => prev.filter(o => o.id !== event.order.id))
      }
    })

    // Fallback polling كل 3 ثواني لو Realtime مش متوفر
    const interval = setInterval(() => {
      if (!isConnected) loadPendingOrders()
    }, 3000)

    return () => {
      unsubscribe()
      clearInterval(interval)
    }
  }, [])

  async function acceptOrder(orderId: string) {
    setAccepting(orderId)
    try {
      const token = await getToken()
      const res = await fetch(`/api/orders/${orderId}/accept`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` }
      })
      const data = await res.json()

      if (res.ok && data.success) {
        toast.success('✅ تم قبول الطلب! اتحرك بسرعة 🛵')
        setPendingOrders(prev => prev.filter(o => o.id !== orderId))
        loadMyOrders()
      } else {
        toast.error(data.error || data.message || 'الطلب اتحجز من مندوب تاني ⚡')
        loadPendingOrders()
      }
    } catch {
      toast.error('في مشكلة في الاتصال')
    } finally {
      setAccepting(null)
    }
  }

  async function updateOnlineStatus() {
    const newStatus = !isOnline
    setIsOnline(newStatus)
    try {
      const token = await getToken()
      await fetch('/api/couriers/online-status', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ isOnline: newStatus })
      })
      toast.success(newStatus ? '🟢 انت دلوقتي متاح' : '🔴 تم إيقاف استقبال الطلبات')
    } catch { /* silent */ }
  }

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black">لوحة المناديب</h1>
          <p className="text-gray-500 text-sm">
            آخر تحديث: {lastRefresh.toLocaleTimeString('ar-EG')}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={loadPendingOrders}
            className="p-2 hover:bg-gray-100 rounded-xl transition-colors"
            title="تحديث"
          >
            <RefreshCw size={18} className={loading ? 'animate-spin text-orange-500' : 'text-gray-500'} />
          </button>
          <button
            onClick={updateOnlineStatus}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm transition-all ${
              isOnline
                ? 'bg-green-100 text-green-700 hover:bg-green-200'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
          >
            {isOnline ? <Wifi size={16} /> : <WifiOff size={16} />}
            {isOnline ? 'متاح' : 'غير متاح'}
          </button>
        </div>
      </div>

      {/* Live Indicator */}
      <div className="flex items-center gap-3 bg-green-50 border border-green-200 rounded-xl px-4 py-3">
        <div className="flex items-center gap-1.5">
          <span className="pulse-dot w-2.5 h-2.5 bg-green-500 rounded-full block" />
          <span className="text-green-700 font-bold text-sm">
            {isConnected ? 'Realtime متصل' : 'Polling كل 3 ثواني'}
          </span>
        </div>
        <span className="text-green-600 text-xs">الطلبات الجديدة بتظهر لحظياً</span>
        <Bell size={16} className="text-green-600 mr-auto" />
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="card text-center py-3 px-2">
          <div className="text-2xl font-black text-orange-500">{pendingOrders.length}</div>
          <div className="text-xs text-gray-500">طلبات جديدة</div>
        </div>
        <div className="card text-center py-3 px-2">
          <div className="text-2xl font-black text-blue-500">
            {myOrders.filter(o => o.status === 'ACCEPTED').length}
          </div>
          <div className="text-xs text-gray-500">جاري التوصيل</div>
        </div>
        <div className="card text-center py-3 px-2">
          <div className="text-2xl font-black text-green-500">
            {myOrders.filter(o => o.status === 'DELIVERED').length}
          </div>
          <div className="text-xs text-gray-500">تم التوصيل</div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl">
        <button
          onClick={() => setTab('pending')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${
            tab === 'pending' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
          }`}
        >
          طلبات جديدة ({pendingOrders.length})
        </button>
        <button
          onClick={() => setTab('mine')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${
            tab === 'mine' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
          }`}
        >
          طلباتي ({myOrders.length})
        </button>
      </div>

      {/* Pending Orders */}
      {tab === 'pending' && (
        <div className="space-y-3">
          {loading ? (
            Array.from({ length: 3 }).map((_, i) => (
              <div key={i} className="card animate-pulse">
                <div className="h-4 bg-gray-200 rounded w-3/4 mb-3" />
                <div className="h-3 bg-gray-200 rounded w-1/2 mb-2" />
                <div className="h-10 bg-gray-200 rounded-xl" />
              </div>
            ))
          ) : pendingOrders.length === 0 ? (
            <div className="text-center py-12">
              <Package size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500 font-semibold">مفيش طلبات جديدة دلوقتي</p>
              <p className="text-gray-400 text-sm">لما يجي طلب هيظهر هنا فوراً</p>
            </div>
          ) : (
            pendingOrders.map(order => (
              <PendingOrderCard
                key={order.id}
                order={order}
                onAccept={acceptOrder}
                accepting={accepting === order.id}
              />
            ))
          )}
        </div>
      )}

      {/* My Orders */}
      {tab === 'mine' && (
        <div className="space-y-3">
          {myOrders.length === 0 ? (
            <div className="text-center py-12">
              <Truck size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">مش عندك طلبات لحد دلوقتي</p>
            </div>
          ) : (
            myOrders.map(order => (
              <MyOrderCard key={order.id} order={order} onStatusUpdate={loadMyOrders} />
            ))
          )}
        </div>
      )}
    </div>
  )
}

function PendingOrderCard({ order, onAccept, accepting }: {
  order: Order
  onAccept: (id: string) => void
  accepting: boolean
}) {
  const timeSince = (date: string) => {
    const mins = Math.floor((Date.now() - new Date(date).getTime()) / 60000)
    if (mins < 1) return 'الآن'
    if (mins < 60) return `منذ ${mins} دقيقة`
    return `منذ ${Math.floor(mins / 60)} ساعة`
  }

  return (
    <div className="card border-r-4 border-orange-500 order-card-enter">
      <div className="flex items-start justify-between mb-3">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-orange-100 rounded-xl flex items-center justify-center">
            {order.type === 'SHOPPING'
              ? <ShoppingBag className="text-orange-500" size={20} />
              : <Truck className="text-orange-500" size={20} />
            }
          </div>
          <div>
            <div className="font-bold text-sm">{order.order_number}</div>
            <div className="text-xs text-gray-400">{timeSince(order.created_at)}</div>
          </div>
        </div>
        <div className="text-left">
          <div className="text-orange-600 font-black text-lg">{order.delivery_fee} ج</div>
          {order.distance_km && (
            <div className="text-xs text-gray-400">{order.distance_km} كم</div>
          )}
        </div>
      </div>

      {order.order_items && order.order_items.length > 0 && (
        <div className="mb-3 bg-gray-50 rounded-xl p-3">
          <div className="text-xs text-gray-500 mb-1 font-semibold">المنتجات:</div>
          {order.order_items.map((item, i) => (
            <div key={i} className="text-sm text-gray-700">
              • {item.name} × {item.quantity}
              {item.shop_name && <span className="text-gray-400"> ({item.shop_name})</span>}
            </div>
          ))}
        </div>
      )}

      <div className="flex items-center gap-1 text-gray-500 text-sm mb-4">
        <MapPin size={14} />
        <span className="truncate">
          {order.pickup_details || 'عنوان الاستلام'} → {order.delivery_details || 'عنوان التوصيل'}
        </span>
      </div>

      <button
        disabled={accepting}
        onClick={() => onAccept(order.id)}
        className="w-full bg-orange-500 hover:bg-orange-600 active:scale-95 text-white font-black py-3 rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-50 text-lg shadow-lg"
      >
        {accepting ? (
          <>
            <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />
            جاري القبول...
          </>
        ) : (
          <>
            <CheckCircle size={22} />
            قبول الطلب ⚡
          </>
        )}
      </button>
    </div>
  )
}

function MyOrderCard({ order, onStatusUpdate }: {
  order: Order
  onStatusUpdate: () => void
}) {
  const { getToken } = useAuth()
  const [updating, setUpdating] = useState(false)

  async function updateStatus(status: string) {
    setUpdating(true)
    try {
      const token = await getToken()
      const res = await fetch(`/api/orders/${order.id}/status`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ status })
      })
      if (res.ok) {
        toast.success('تم تحديث الحالة')
        onStatusUpdate()
      }
    } catch { /* ignore */ } finally {
      setUpdating(false)
    }
  }

  return (
    <div className="card">
      <div className="flex items-center justify-between mb-3">
        <div className="font-bold">{order.order_number}</div>
        <span className={STATUS_COLORS[order.status]}>{STATUS_LABELS[order.status]}</span>
      </div>
      <div className="text-sm text-gray-500 mb-3">
        <div className="flex items-center gap-1">
          <Clock size={14} />
          {new Date(order.created_at).toLocaleString('ar-EG')}
        </div>
        <div className="font-bold text-orange-600 mt-1">{order.delivery_fee} جنيه</div>
      </div>
      {order.status === 'ACCEPTED' && (
        <button
          disabled={updating}
          onClick={() => updateStatus('PICKED_UP')}
          className="w-full btn-primary text-sm py-2"
        >
          {updating ? '...' : '📦 تأكيد الاستلام'}
        </button>
      )}
      {order.status === 'PICKED_UP' && (
        <button
          disabled={updating}
          onClick={() => updateStatus('DELIVERED')}
          className="w-full bg-green-500 hover:bg-green-600 text-white font-bold py-2 rounded-xl text-sm transition-all"
        >
          {updating ? '...' : '✅ تأكيد التوصيل'}
        </button>
      )}
    </div>
  )
}

