interface CourierProfile {
  id: string
  name: string
  phone: string
  address: string
  status: string
  rating: number
  total_deliveries: number
  is_online: boolean
  created_at: string
  averageRating: number
  totalRatings: number
  courier_ratings: { rating: number; comment?: string; created_at: string }[]
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  PENDING_REVIEW: { label: '⏳ قيد المراجعة', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  APPROVED: { label: '✅ معتمد', color: 'text-green-700', bg: 'bg-green-100' },
  REJECTED: { label: '❌ مرفوض', color: 'text-red-700', bg: 'bg-red-100' },
  SUSPENDED: { label: '🚫 موقوف', color: 'text-gray-700', bg: 'bg-gray-100' },
}

export default function CourierProfile() {
  const { getToken } = useAuth()
  const [profile, setProfile] = useState<CourierProfile | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function load() {
      try {
        const token = await getToken()
        const res = await fetch('/api/couriers/profile', {
          headers: { Authorization: `Bearer ${token}` }
        })
        if (res.ok) {
          const data = await res.json()
          setProfile(data.courier)
        } else {
          // Demo data
          setProfile(DEMO_PROFILE)
        }
      } catch {
        setProfile(DEMO_PROFILE)
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [])

  if (loading) {
    return (
      <div className="space-y-4">
        {Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-24" />
        ))}
