import { useState, useEffect } from 'react'
import { useAuth } from '@clerk/clerk-react'
import toast from 'react-hot-toast'
import { Settings, Plus, Save, MapPin } from 'lucide-react'

interface PricingZone {
  id?: string
  zone: string
  price_per_km: number
  minimum_fee: number
  maximum_fee?: number
  is_active: boolean
}

const DEFAULT_ZONES: PricingZone[] = [
  { zone: 'cairo', price_per_km: 8, minimum_fee: 20, maximum_fee: 80, is_active: true },
  { zone: 'giza', price_per_km: 9, minimum_fee: 25, maximum_fee: 90, is_active: true },
  { zone: 'default', price_per_km: 10, minimum_fee: 30, maximum_fee: 100, is_active: true },
]

const ZONE_NAMES: Record<string, string> = {
  cairo: 'القاهرة',
  giza: 'الجيزة',
  default: 'المناطق الأخرى',
}

export default function AdminPricing() {
  const { getToken } = useAuth()
  const [zones, setZones] = useState<PricingZone[]>(DEFAULT_ZONES)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState<string | null>(null)
  const [showAddForm, setShowAddForm] = useState(false)
  const [newZone, setNewZone] = useState<PricingZone>({
    zone: '', price_per_km: 8, minimum_fee: 20, is_active: true
  })

  useEffect(() => {
    async function load() {
      try {
        const token = await getToken()
        const res = await fetch('/api/admin/pricing', {
          headers: { Authorization: `Bearer ${token}` }
        })
        if (res.ok) {
          const data = await res.json()
          if (data.pricing?.length > 0) setZones(data.pricing)
        }
      } catch { /* use defaults */ } finally {
        setLoading(false)
      }
    }
    load()
  }, [])

  async function saveZone(zone: PricingZone) {
    setSaving(zone.zone)
    try {
      const token = await getToken()
      const res = await fetch('/api/admin/pricing', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          zone: zone.zone,
          pricePerKm: zone.price_per_km,
          minimumFee: zone.minimum_fee,
          maximumFee: zone.maximum_fee,
          isActive: zone.is_active,
        })
      })
      if (res.ok) {
        toast.success(`تم حفظ سعر ${ZONE_NAMES[zone.zone] || zone.zone}`)
      } else {
        toast.error('مقدرناش نحفظ السعر')
      }
    } catch {
      toast.success('تم الحفظ (Demo Mode)')
    } finally {
      setSaving(null)
    }
  }

  async function addNewZone() {
    if (!newZone.zone.trim()) {
      toast.error('ادخل اسم المنطقة')
      return
    }
    const zone = { ...newZone }
    setZones([...zones, zone])
    await saveZone(zone)
    setShowAddForm(false)
    setNewZone({ zone: '', price_per_km: 8, minimum_fee: 20, is_active: true })
  }

  const updateZone = (zoneName: string, field: keyof PricingZone, value: number | boolean | string) => {
    setZones(zones.map(z => z.zone === zoneName ? { ...z, [field]: value } : z))
  }

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Settings className="text-orange-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">إدارة الأسعار</h1>
            <p className="text-gray-500 text-sm">سعر التوصيل بالكيلو لكل منطقة</p>
          </div>
        </div>
        <button
          onClick={() => setShowAddForm(!showAddForm)}
          className="btn-primary text-sm px-4 py-2 flex items-center gap-2"
        >
          <Plus size={16} />
          منطقة جديدة
        </button>
      </div>

      {/* Pricing Formula Info */}
      <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
        <strong>📐 طريقة الحساب:</strong>
        <br />
        سعر التوصيل = (المسافة بالكيلو × سعر الكيلو) + ثم مقارنة بالحد الأدنى
        <br />
        مثال: 3 كم × 8 جنيه = 24 جنيه، لكن الحد الأدنى 25 جنيه → يتحسب 25 جنيه
      </div>

      {/* Add Zone Form */}
      {showAddForm && (
        <div className="card border-2 border-orange-200 animate-fade-in">
          <h3 className="font-bold mb-4">إضافة منطقة جديدة</h3>
          <div className="grid grid-cols-2 gap-3 mb-3">
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">اسم المنطقة (بالإنجليزية)</label>
              <input
                className="input text-sm"
                placeholder="مثال: nasr-city"
                value={newZone.zone}
                onChange={e => setNewZone({ ...newZone, zone: e.target.value.toLowerCase() })}
                dir="ltr"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">سعر الكيلو (جنيه)</label>
              <input
                type="number"
                className="input text-sm"
                value={newZone.price_per_km}
                onChange={e => setNewZone({ ...newZone, price_per_km: parseFloat(e.target.value) })}
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">الحد الأدنى (جنيه)</label>
              <input
                type="number"
                className="input text-sm"
                value={newZone.minimum_fee}
                onChange={e => setNewZone({ ...newZone, minimum_fee: parseFloat(e.target.value) })}
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">الحد الأقصى (جنيه)</label>
              <input
                type="number"
                className="input text-sm"
                placeholder="اختياري"
                onChange={e => setNewZone({ ...newZone, maximum_fee: parseFloat(e.target.value) || undefined })}
              />
            </div>
          </div>
          <button onClick={addNewZone} className="btn-primary text-sm px-4 py-2">
            إضافة المنطقة
          </button>
        </div>
      )}

      {/* Zone Cards */}
      {loading ? (
        Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-32" />
        ))
      ) : (
        zones.map(zone => (
          <div key={zone.zone} className="card">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <MapPin className="text-orange-500" size={20} />
                <h3 className="font-bold">{ZONE_NAMES[zone.zone] || zone.zone}</h3>
                <span className="text-xs text-gray-400">({zone.zone})</span>
              </div>
              <label className="flex items-center gap-2 cursor-pointer">
                <span className="text-xs font-semibold text-gray-600">نشط</span>
                <div
                  onClick={() => updateZone(zone.zone, 'is_active', !zone.is_active)}
                  className={`w-10 h-6 rounded-full transition-all cursor-pointer ${zone.is_active ? 'bg-green-500' : 'bg-gray-300'}`}
                >
                  <div className={`w-5 h-5 bg-white rounded-full shadow transition-all m-0.5 ${zone.is_active ? 'translate-x-4' : 'translate-x-0'}`} />
                </div>
              </label>
            </div>

            <div className="grid grid-cols-3 gap-3 mb-4">
              <div>
                <label className="block text-xs font-semibold text-gray-600 mb-1">سعر الكيلو</label>
                <div className="flex items-center gap-1">
                  <input
                    type="number"
                    className="input text-sm"
                    value={zone.price_per_km}
                    step="0.5"
                    min="1"
                    onChange={e => updateZone(zone.zone, 'price_per_km', parseFloat(e.target.value))}
                  />
                  <span className="text-xs text-gray-500 whitespace-nowrap">ج/كم</span>
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-600 mb-1">الحد الأدنى</label>
                <div className="flex items-center gap-1">
                  <input
                    type="number"
                    className="input text-sm"
                    value={zone.minimum_fee}
                    min="5"
                    onChange={e => updateZone(zone.zone, 'minimum_fee', parseFloat(e.target.value))}
                  />
                  <span className="text-xs text-gray-500">ج</span>
                </div>
              </div>
              <div>
                <label className="block text-xs font-semibold text-gray-600 mb-1">الحد الأقصى</label>
                <div className="flex items-center gap-1">
                  <input
                    type="number"
                    className="input text-sm"
                    value={zone.maximum_fee || ''}
                    placeholder="∞"
                    onChange={e => updateZone(zone.zone, 'maximum_fee', parseFloat(e.target.value) || 0)}
                  />
                  <span className="text-xs text-gray-500">ج</span>
                </div>
              </div>
            </div>

            {/* Preview */}
            <div className="bg-gray-50 rounded-xl p-3 text-sm text-gray-600 mb-4">
              <strong>مثال:</strong> 5 كم × {zone.price_per_km} = {(5 * zone.price_per_km).toFixed(0)} جنيه
              {5 * zone.price_per_km < zone.minimum_fee && (
                <span className="text-orange-600"> → الحد الأدنى: {zone.minimum_fee} جنيه</span>
              )}
            </div>

            <button
              disabled={saving === zone.zone}
              onClick={() => saveZone(zone)}
              className="btn-primary text-sm px-4 py-2 flex items-center gap-2"
            >
              {saving === zone.zone ? (
                <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent" />
              ) : (
                <Save size={16} />
              )}
              حفظ
            </button>
          </div>
        ))
      )}
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useAuth } from '@clerk/clerk-react'
import toast from 'react-hot-toast'
import { Megaphone, Plus, Eye, EyeOff, TrendingUp } from 'lucide-react'

interface AdOffer {
  id: string
  title: string
  description?: string
  image_url: string
  shop_name: string
  shop_address: string
  shop_lat: number
  shop_lng: number
  product_name: string
  product_price?: number
  is_active: boolean
  click_count: number
  start_date: string
  end_date: string
}

const EMPTY_AD = {
  title: '',
  description: '',
  image_url: '',
  shop_name: '',
  shop_address: '',
  shop_lat: 30.0444,
  shop_lng: 31.2357,
  product_name: '',
  product_price: 0,
  start_date: new Date().toISOString().split('T')[0],
  end_date: new Date(Date.now() + 7 * 86400000).toISOString().split('T')[0],
}

export default function AdminAds() {
  const { getToken } = useAuth()
  const [ads, setAds] = useState<AdOffer[]>([])
  const [loading, setLoading] = useState(true)
  const [showForm, setShowForm] = useState(false)
  const [form, setForm] = useState(EMPTY_AD)
  const [submitting, setSubmitting] = useState(false)

  useEffect(() => {
    loadAds()
  }, [])

  async function loadAds() {
    try {
      const token = await getToken()
      const res = await fetch('/api/admin/ads', {
        headers: { Authorization: `Bearer ${token}` }
      })
      if (res.ok) {
        const data = await res.json()
        setAds(data.ads || [])
      } else {
        setAds(DEMO_ADS)
      }
    } catch {
      setAds(DEMO_ADS)
    } finally {
      setLoading(false)
    }
  }

  async function createAd() {
    if (!form.title || !form.shop_name || !form.product_name) {
      toast.error('ملء البيانات المطلوبة')
      return
    }
    setSubmitting(true)
    try {
      const token = await getToken()
      const res = await fetch('/api/admin/ads', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          title: form.title,
          description: form.description,
          imageUrl: form.image_url || 'https://placehold.co/400x250/f97316/white?text=عرض',
          shopName: form.shop_name,
          shopAddress: form.shop_address,
          shopLat: form.shop_lat,
          shopLng: form.shop_lng,
          productName: form.product_name,
          productPrice: form.product_price || undefined,
          startDate: new Date(form.start_date).toISOString(),
          endDate: new Date(form.end_date).toISOString(),
        })
      })
      if (res.ok) {
        toast.success('تم نشر العرض!')
        setShowForm(false)
        setForm(EMPTY_AD)
        loadAds()
      } else {
        toast.error('مقدرناش ننشر العرض')
      }
    } catch {
      toast.success('تم الإنشاء (Demo Mode)')
      setShowForm(false)
    } finally {
      setSubmitting(false)
    }
  }

  async function toggleAd(id: string, isActive: boolean) {
    try {
      const token = await getToken()
      await fetch(`/api/admin/ads/${id}`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ is_active: !isActive })
      })
      setAds(ads.map(a => a.id === id ? { ...a, is_active: !isActive } : a))
      toast.success(isActive ? 'تم إيقاف العرض' : 'تم تفعيل العرض')
    } catch {
      setAds(ads.map(a => a.id === id ? { ...a, is_active: !isActive } : a))
    }
  }

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Megaphone className="text-orange-500" size={28} />
          <div>
            <h1 className="text-2xl font-black">إدارة العروض</h1>
            <p className="text-gray-500 text-sm">إعلانات المطاعم والمحلات</p>
          </div>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="btn-primary text-sm px-4 py-2 flex items-center gap-2"
        >
          <Plus size={16} />
          عرض جديد
        </button>
      </div>

      {/* Create Form */}
      {showForm && (
        <div className="card border-2 border-orange-200 animate-fade-in space-y-4">
          <h3 className="font-bold text-lg">إنشاء عرض جديد</h3>

          <div className="grid grid-cols-2 gap-3">
            <div className="col-span-2">
              <label className="block text-xs font-semibold text-gray-600 mb-1">عنوان العرض *</label>
              <input className="input text-sm" placeholder="بيتزا مارجريتا بـ 89 جنيه بدل 120!" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">اسم المحل *</label>
              <input className="input text-sm" placeholder="بيتزا كينج" value={form.shop_name} onChange={e => setForm({ ...form, shop_name: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">اسم المنتج *</label>
              <input className="input text-sm" placeholder="بيتزا مارجريتا كبيرة" value={form.product_name} onChange={e => setForm({ ...form, product_name: e.target.value })} />
            </div>
            <div className="col-span-2">
              <label className="block text-xs font-semibold text-gray-600 mb-1">عنوان المحل</label>
              <input className="input text-sm" placeholder="شارع التحرير، القاهرة" value={form.shop_address} onChange={e => setForm({ ...form, shop_address: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">سعر المنتج (جنيه)</label>
              <input type="number" className="input text-sm" value={form.product_price || ''} onChange={e => setForm({ ...form, product_price: parseFloat(e.target.value) })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">رابط الصورة</label>
              <input className="input text-sm" placeholder="https://..." dir="ltr" value={form.image_url} onChange={e => setForm({ ...form, image_url: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">تاريخ البداية</label>
              <input type="date" className="input text-sm" value={form.start_date} onChange={e => setForm({ ...form, start_date: e.target.value })} />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 mb-1">تاريخ النهاية</label>
              <input type="date" className="input text-sm" value={form.end_date} onChange={e => setForm({ ...form, end_date: e.target.value })} />
            </div>
            <div className="col-span-2">
              <label className="block text-xs font-semibold text-gray-600 mb-1">وصف (اختياري)</label>
              <textarea className="input text-sm resize-none h-16" placeholder="وصف إضافي للعرض..." value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
            </div>
          </div>

          <div className="flex gap-3">
            <button disabled={submitting} onClick={createAd} className="btn-primary text-sm px-6 py-2">
              {submitting ? 'جاري النشر...' : 'نشر العرض'}
            </button>
            <button onClick={() => setShowForm(false)} className="btn-secondary text-sm px-6 py-2">
              إلغاء
            </button>
          </div>
        </div>
      )}

      {/* Ads List */}
      {loading ? (
        Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-32" />
        ))
      ) : ads.length === 0 ? (
        <div className="text-center py-12">
          <Megaphone size={48} className="mx-auto mb-3 text-gray-300" />
          <p className="text-gray-500">مفيش عروض لحد دلوقتي</p>
          <button onClick={() => setShowForm(true)} className="mt-4 text-orange-500 font-bold">
            أنشئ أول عرض
          </button>
        </div>
      ) : (
        ads.map(ad => (
          <div key={ad.id} className={`card overflow-hidden p-0 ${!ad.is_active ? 'opacity-60' : ''}`}>
            <div className="flex">
              <img
                src={ad.image_url}
                alt={ad.title}
                className="w-28 h-28 object-cover flex-shrink-0"
                onError={e => { (e.target as HTMLImageElement).src = 'https://placehold.co/120x120/f97316/white?text=عرض' }}
              />
              <div className="p-4 flex-1">
                <div className="flex items-start justify-between">
                  <h3 className="font-bold text-sm line-clamp-2 flex-1">{ad.title}</h3>
                  <button
                    onClick={() => toggleAd(ad.id, ad.is_active)}
                    className={`mr-2 p-1.5 rounded-lg transition-all ${ad.is_active ? 'bg-green-100 text-green-600 hover:bg-green-200' : 'bg-gray-100 text-gray-400 hover:bg-gray-200'}`}
                  >
                    {ad.is_active ? <Eye size={16} /> : <EyeOff size={16} />}
                  </button>
                </div>
                <p className="text-xs text-gray-500 mt-1">{ad.shop_name}</p>
                {ad.product_price && (
                  <p className="text-orange-500 font-bold text-sm mt-1">{ad.product_price} جنيه</p>
                )}
                <div className="flex items-center gap-1 text-xs text-gray-400 mt-2">
                  <TrendingUp size={12} />
                  <span>{ad.click_count} ضغطة</span>
                </div>
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  )
}

const DEMO_ADS: AdOffer[] = [
  {
    id: '1', title: 'بيتزا مارجريتا بـ 89 جنيه', image_url: 'https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=120&h=120&fit=crop',
    shop_name: 'بيتزا كينج', shop_address: 'شارع التحرير', shop_lat: 30.044, shop_lng: 31.235,
    product_name: 'بيتزا مارجريتا', product_price: 89, is_active: true, click_count: 142,
    start_date: new Date().toISOString(), end_date: new Date(Date.now() + 86400000).toISOString(),
  },
]

import { useState, useEffect } from 'react'
import { useAuth } from '@clerk/clerk-react'
import toast from 'react-hot-toast'
import { Truck, CheckCircle, XCircle, Clock, Star, Phone, MapPin } from 'lucide-react'

interface Courier {
  id: string
  name: string
  phone: string
  address: string
  status: string
  rating: number
  total_deliveries: number
  id_front_image_url: string
  id_back_image_url: string
  created_at: string
  users?: { email: string }
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  PENDING_REVIEW: { label: 'قيد المراجعة', color: 'text-yellow-700', bg: 'bg-yellow-100' },
  APPROVED: { label: 'معتمد', color: 'text-green-700', bg: 'bg-green-100' },
  REJECTED: { label: 'مرفوض', color: 'text-red-700', bg: 'bg-red-100' },
  SUSPENDED: { label: 'موقوف', color: 'text-gray-700', bg: 'bg-gray-100' },
}

export default function AdminCouriers() {
  const { getToken } = useAuth()
  const [couriers, setCouriers] = useState<Courier[]>([])
  const [loading, setLoading] = useState(true)
  const [filter, setFilter] = useState<string>('all')
  const [updating, setUpdating] = useState<string | null>(null)
  const [selectedCourier, setSelectedCourier] = useState<Courier | null>(null)

  useEffect(() => { loadCouriers() }, [filter])

  async function loadCouriers() {
    setLoading(true)
    try {
      const token = await getToken()
      const url = filter === 'all' ? '/api/admin/couriers' : `/api/admin/couriers?status=${filter}`
      const res = await fetch(url, { headers: { Authorization: `Bearer ${token}` } })
      if (res.ok) {
        const data = await res.json()
        setCouriers(data.couriers || [])
      } else {
        setCouriers(DEMO_COURIERS)
      }
    } catch {
      setCouriers(DEMO_COURIERS)
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(courierId: string, status: string) {
    setUpdating(courierId)
    try {
      const token = await getToken()
      const res = await fetch(`/api/admin/couriers/${courierId}/approve`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ status })
      })
      if (res.ok) {
        toast.success(status === 'APPROVED' ? '✅ تم الموافقة على المندوب' : '❌ تم رفض المندوب')
        setCouriers(couriers.map(c => c.id === courierId ? { ...c, status } : c))
        setSelectedCourier(null)
      } else {
        toast.error('مقدرناش نحدث الحالة')
      }
    } catch {
      // Demo mode
      toast.success(status === 'APPROVED' ? '✅ تم الموافقة (Demo)' : '❌ تم الرفض (Demo)')
      setCouriers(couriers.map(c => c.id === courierId ? { ...c, status } : c))
      setSelectedCourier(null)
    } finally {
      setUpdating(null)
    }
  }

  const filtered = filter === 'all' ? couriers : couriers.filter(c => c.status === filter)
  const pendingCount = couriers.filter(c => c.status === 'PENDING_REVIEW').length

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Truck className="text-orange-500" size={28} />
        <div>
          <h1 className="text-2xl font-black">إدارة المناديب</h1>
          {pendingCount > 0 && (
            <p className="text-yellow-600 text-sm font-semibold">{pendingCount} مندوب ينتظر الموافقة ⏳</p>
          )}
        </div>
      </div>

      {/* Filter Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl overflow-x-auto">
        {[
          { key: 'all', label: `الكل (${couriers.length})` },
          { key: 'PENDING_REVIEW', label: `منتظر (${couriers.filter(c => c.status === 'PENDING_REVIEW').length})` },
          { key: 'APPROVED', label: `معتمد (${couriers.filter(c => c.status === 'APPROVED').length})` },
          { key: 'REJECTED', label: `مرفوض (${couriers.filter(c => c.status === 'REJECTED').length})` },
        ].map(tab => (
          <button
            key={tab.key}
            onClick={() => setFilter(tab.key)}
            className={`flex-shrink-0 px-3 py-2 rounded-lg font-bold text-xs transition-all ${
              filter === tab.key ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Couriers List */}
      {loading ? (
        Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="card animate-pulse h-24" />
        ))
      ) : filtered.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Truck size={48} className="mx-auto mb-3 opacity-30" />
          <p>مفيش مناديب في هذه الفئة</p>
        </div>
      ) : (
        filtered.map(courier => {
          const statusConfig = STATUS_CONFIG[courier.status]
          return (
            <div key={courier.id} className="card">
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-orange-100 rounded-xl flex items-center justify-center flex-shrink-0">
                    <span className="text-orange-600 font-black text-lg">{courier.name[0]}</span>
                  </div>
                  <div>
                    <h3 className="font-bold">{courier.name}</h3>
                    <div className="flex items-center gap-1 text-sm text-gray-500">
                      <Phone size={12} />
                      <span dir="ltr">{courier.phone}</span>
                    </div>
                  </div>
                </div>
                <span className={`text-xs font-bold px-2 py-1 rounded-full ${statusConfig.bg} ${statusConfig.color}`}>
                  {statusConfig.label}
                </span>
              </div>

              <div className="mt-3 flex items-center gap-4 text-xs text-gray-500">
                <div className="flex items-center gap-1">
                  <Star size={12} className="text-yellow-400" />
                  {courier.rating.toFixed(1)}
                </div>
                <div className="flex items-center gap-1">
                  <Truck size={12} />
                  {courier.total_deliveries} توصيلة
                </div>
                <div className="flex items-center gap-1">
                  <Clock size={12} />
                  {new Date(courier.created_at).toLocaleDateString('ar-EG')}
                </div>
              </div>

              {courier.status === 'PENDING_REVIEW' && (
                <div className="mt-4 space-y-3">
                  {/* Show ID images */}
                  <div className="grid grid-cols-2 gap-2">
                    <div className="bg-gray-100 rounded-xl p-2 text-center text-xs text-gray-500">
                      🪪 وجه البطاقة
                      <div className="text-xs text-gray-400 mt-1">
                        {courier.id_front_image_url ? '✅ مرفوع' : '❌ مش موجود'}
                      </div>
                    </div>
                    <div className="bg-gray-100 rounded-xl p-2 text-center text-xs text-gray-500">
                      🪪 ضهر البطاقة
                      <div className="text-xs text-gray-400 mt-1">
                        {courier.id_back_image_url ? '✅ مرفوع' : '❌ مش موجود'}
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button
                      disabled={updating === courier.id}
                      onClick={() => updateStatus(courier.id, 'APPROVED')}
                      className="flex-1 bg-green-500 hover:bg-green-600 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-1 transition-all"
                    >
                      <CheckCircle size={16} />
                      موافقة
                    </button>
                    <button
                      disabled={updating === courier.id}
                      onClick={() => updateStatus(courier.id, 'REJECTED')}
                      className="flex-1 bg-red-500 hover:bg-red-600 text-white font-bold py-2.5 rounded-xl text-sm flex items-center justify-center gap-1 transition-all"
                    >
                      <XCircle size={16} />
                      رفض
                    </button>
                  </div>
                </div>
              )}

              {courier.status === 'APPROVED' && (
                <button
                  disabled={updating === courier.id}
                  onClick={() => updateStatus(courier.id, 'SUSPENDED')}
                  className="mt-3 w-full bg-gray-100 hover:bg-red-50 text-gray-600 hover:text-red-600 font-bold py-2 rounded-xl text-sm transition-all"
                >
                  إيقاف المندوب
                </button>
              )}

              {courier.status === 'SUSPENDED' && (
                <button
                  disabled={updating === courier.id}
                  onClick={() => updateStatus(courier.id, 'APPROVED')}
                  className="mt-3 w-full bg-green-100 hover:bg-green-200 text-green-700 font-bold py-2 rounded-xl text-sm transition-all"
                >
                  إعادة التفعيل
                </button>
