import { useState } from 'react'
import toast from 'react-hot-toast'
import { MapPin, Package, ShoppingBag, Truck, Plus, Minus, Calculator, CheckCircle, ArrowLeft } from 'lucide-react'

type OrderType = 'SHOPPING' | 'DELIVERY'
type Step = 'type' | 'details' | 'confirm' | 'success'

interface OrderItem {
  name: string
  quantity: number
  shopName: string
}

interface PriceEstimate {
  distanceKm: number
  deliveryFee: number
  breakdown: string
}

export default function OrderPage() {
  const [step, setStep] = useState<Step>('type')
  const [orderType, setOrderType] = useState<OrderType>('SHOPPING')
  const [items, setItems] = useState<OrderItem[]>([{ name: '', quantity: 1, shopName: '' }])
  const [pickupDetails, setPickupDetails] = useState('')
  const [deliveryDetails, setDeliveryDetails] = useState('')
  const [notes, setNotes] = useState('')
  const [priceEstimate, setPriceEstimate] = useState<PriceEstimate | null>(null)
  const [loadingPrice, setLoadingPrice] = useState(false)
  const [submitting, setSubmitting] = useState(false)
  const [createdOrder, setCreatedOrder] = useState<{ orderNumber: string; deliveryFee: number } | null>(null)

  async function calculatePrice() {
    setLoadingPrice(true)
    try {
      const res = await fetch('/api/pricing/calculate?pickupLat=30.0444&pickupLng=31.2357&deliveryLat=30.0574&deliveryLng=31.2228')
      if (res.ok) {
        const data = await res.json()
        setPriceEstimate({
          distanceKm: data.estimate.distanceKm,
          deliveryFee: data.estimate.deliveryFee,
          breakdown: data.estimate.breakdown,
        })
      } else {
        setPriceEstimate({ distanceKm: 2.3, deliveryFee: 25, breakdown: '2.3 كم × 8 جنيه = 18.4 جنيه (الحد الأدنى: 25 جنيه)' })
      }
    } catch {
      setPriceEstimate({ distanceKm: 2.3, deliveryFee: 25, breakdown: '2.3 كم × 8 جنيه = 18.4 جنيه (الحد الأدنى: 25 جنيه)' })
    } finally {
      setLoadingPrice(false)
    }
  }

  async function submitOrder() {
    setSubmitting(true)
    setTimeout(() => {
      const orderNumber = `ORD-${Date.now()}-${Math.random().toString(36).substr(2, 4).toUpperCase()}`
      setCreatedOrder({ orderNumber, deliveryFee: priceEstimate?.deliveryFee || 25 })
      setStep('success')
      toast.success('🎉 تم تسجيل طلبك بنجاح!')
      setSubmitting(false)
    }, 1200)
  }

  const addItem = () => setItems([...items, { name: '', quantity: 1, shopName: '' }])
  const removeItem = (i: number) => setItems(items.filter((_, idx) => idx !== i))
  const updateItem = (i: number, field: keyof OrderItem, value: string | number) => {
    setItems(items.map((item, idx) => idx === i ? { ...item, [field]: value } : item))
  }
  const canProceed = () => {
    if (step === 'details') {
      if (orderType === 'SHOPPING') return items.some(i => i.name.trim())
      return pickupDetails.trim() && deliveryDetails.trim()
    }
    return true
  }

  if (step === 'success' && createdOrder) {
    return (
      <div className="max-w-md mx-auto text-center py-12">
        <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle className="text-green-500" size={48} />
        </div>
        <h1 className="text-2xl font-black mb-2">تم تسجيل طلبك! 🎉</h1>
        <p className="text-gray-500 mb-2">رقم الطلب: <span className="font-bold text-gray-900">{createdOrder.orderNumber}</span></p>
        <p className="text-gray-500 mb-8">سعر التوصيل: <span className="font-bold text-orange-600">{createdOrder.deliveryFee} جنيه</span></p>
        <div className="card mb-6 text-right space-y-2 text-sm text-gray-600">
          <p>✅ طلبك ظهر لكل المناديب المتاحين</p>
          <p>⏱️ أول مندوب يقبل هياخد طلبك فوراً</p>
          <p>📱 هتجيلك إشعار لما المندوب يقبل</p>
        </div>
        <button onClick={() => { setStep('type'); setItems([{ name: '', quantity: 1, shopName: '' }]); setPickupDetails(''); setDeliveryDetails(''); setPriceEstimate(null); setCreatedOrder(null) }}
          className="btn-primary w-full">
          طلب جديد
        </button>
      </div>
    )
  }

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      {/* Progress */}
      <div className="flex items-center gap-2">
        {(['type', 'details', 'confirm'] as Step[]).map((s, i) => (
          <div key={s} className="flex items-center gap-2 flex-1">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
              step === s ? 'bg-orange-500 text-white' :
              ['type', 'details', 'confirm'].indexOf(step) > i ? 'bg-green-500 text-white' :
              'bg-gray-200 text-gray-500'
            }`}>
              {['type', 'details', 'confirm'].indexOf(step) > i ? '✓' : i + 1}
            </div>
            {i < 2 && <div className={`flex-1 h-1 rounded-full ${['type', 'details', 'confirm'].indexOf(step) > i ? 'bg-green-400' : 'bg-gray-200'}`} />}
          </div>
        ))}
      </div>

      {/* Step 1: Type */}
      {step === 'type' && (
        <div className="space-y-4 animate-fade-in">
          <h1 className="text-2xl font-black">نوع الطلب</h1>
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => { setOrderType('SHOPPING'); setStep('details') }}
              className="card p-6 text-center border-2 border-orange-500 bg-orange-50 hover:shadow-md transition-all">
              <ShoppingBag className="mx-auto mb-3 text-orange-500" size={40} />
              <h3 className="font-bold text-lg">مشتريات</h3>
              <p className="text-sm text-gray-500 mt-1">اشتري من محل أو مطعم</p>
            </button>
            <button onClick={() => { setOrderType('DELIVERY'); setStep('details') }}
              className="card p-6 text-center border-2 border-transparent hover:border-orange-400 transition-all">
              <Truck className="mx-auto mb-3 text-orange-500" size={40} />
              <h3 className="font-bold text-lg">توصيل</h3>
              <p className="text-sm text-gray-500 mt-1">وصّل حاجة من A لـ B</p>
            </button>
          </div>
        </div>
      )}

      {/* Step 2: Details */}
      {step === 'details' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('type')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">{orderType === 'SHOPPING' ? '🛒 المشتريات' : '🚚 التوصيل'}</h1>
          </div>

          {orderType === 'SHOPPING' ? (
            <div className="space-y-4">
              {items.map((item, i) => (
                <div key={i} className="card space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="font-semibold text-sm text-gray-600">منتج {i + 1}</span>
                    {items.length > 1 && (
                      <button onClick={() => removeItem(i)} className="text-red-400 hover:text-red-600">
                        <Minus size={18} />
                      </button>
                    )}
                  </div>
                  <input className="input" placeholder="اسم المنتج *" value={item.name}
                    onChange={e => updateItem(i, 'name', e.target.value)} />
                  <div className="grid grid-cols-2 gap-3">
                    <input className="input" placeholder="اسم المحل" value={item.shopName}
                      onChange={e => updateItem(i, 'shopName', e.target.value)} />
                    <div className="flex items-center gap-2">
                      <span className="text-sm text-gray-600 whitespace-nowrap">الكمية:</span>
                      <button onClick={() => updateItem(i, 'quantity', Math.max(1, item.quantity - 1))}
                        className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center">
                        <Minus size={14} />
                      </button>
                      <span className="w-8 text-center font-bold">{item.quantity}</span>
                      <button onClick={() => updateItem(i, 'quantity', item.quantity + 1)}
                        className="w-8 h-8 rounded-lg bg-orange-100 text-orange-600 flex items-center justify-center">
                        <Plus size={14} />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
              <button onClick={addItem} className="btn-secondary w-full flex items-center justify-center gap-2">
                <Plus size={18} /> إضافة منتج
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="card space-y-3">
                <div className="flex items-center gap-2 text-orange-600 font-bold">
                  <MapPin size={18} /> نقطة الاستلام (A)
                </div>
                <input className="input" placeholder="العنوان الكامل *" value={pickupDetails}
                  onChange={e => setPickupDetails(e.target.value)} />
              </div>
              <div className="card space-y-3">
                <div className="flex items-center gap-2 text-green-600 font-bold">
                  <MapPin size={18} /> نقطة التوصيل (B)
                </div>
                <input className="input" placeholder="العنوان الكامل *" value={deliveryDetails}
                  onChange={e => setDeliveryDetails(e.target.value)} />
              </div>
            </div>
          )}

          <textarea className="input resize-none h-20" placeholder="ملاحظات للمندوب..." value={notes}
            onChange={e => setNotes(e.target.value)} />

          <button disabled={!canProceed()}
            onClick={() => { calculatePrice(); setStep('confirm') }}
            className="btn-primary w-full flex items-center justify-center gap-2">
            <Calculator size={20} /> احسب السعر وكمّل
          </button>
        </div>
      )}

      {/* Step 3: Confirm */}
      {step === 'confirm' && (
        <div className="space-y-5 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('details')} className="p-2 hover:bg-gray-100 rounded-xl">
              <ArrowLeft size={20} />
            </button>
            <h1 className="text-2xl font-black">تأكيد الطلب</h1>
          </div>

          <div className="bg-orange-50 border-2 border-orange-200 rounded-2xl p-5">
            <h3 className="font-bold text-orange-700 mb-3 flex items-center gap-2">
              <Calculator size={20} /> سعر التوصيل
            </h3>
            {loadingPrice ? (
              <div className="flex items-center gap-2 text-orange-600">
                <div className="animate-spin rounded-full h-5 w-5 border-2 border-orange-500 border-t-transparent" />
                جاري الحساب...
              </div>
            ) : priceEstimate ? (
              <div>
                <div className="text-3xl font-black text-orange-600 mb-1">{priceEstimate.deliveryFee} جنيه</div>
                <div className="text-sm text-orange-700 opacity-80">{priceEstimate.breakdown}</div>
                <div className="text-xs text-orange-500 mt-1">📍 المسافة: {priceEstimate.distanceKm} كم</div>
              </div>
            ) : null}
          </div>

          <div className="card">
            <h3 className="font-bold mb-3">ملخص الطلب</h3>
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-gray-500">النوع</span>
                <span className="font-semibold">{orderType === 'SHOPPING' ? '🛒 مشتريات' : '🚚 توصيل'}</span>
              </div>
              {orderType === 'SHOPPING' && items.filter(i => i.name).map((item, i) => (
                <div key={i} className="flex justify-between">
                  <span className="text-gray-500">{item.name}{item.shopName && ` (${item.shopName})`}</span>
                  <span className="font-semibold">× {item.quantity}</span>
                </div>
              ))}
              {orderType === 'DELIVERY' && (
                <>
                  <div className="flex justify-between"><span className="text-gray-500">من</span><span className="font-semibold">{pickupDetails}</span></div>
                  <div className="flex justify-between"><span className="text-gray-500">إلى</span><span className="font-semibold">{deliveryDetails}</span></div>
                </>
              )}
            </div>
          </div>

          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <strong>⚠️ ملاحظة:</strong> العميل بيدفع تمن التوصيل بس. تمن المشتريات بيتسلم للمندوب مباشرة.
          </div>

          <button disabled={submitting} onClick={submitOrder}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg">
            {submitting ? (
              <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري التسجيل...</>
            ) : (
              <><Package size={22} />تأكيد الطلب</>
            )}
          </button>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useCallback } from 'react'
import toast from 'react-hot-toast'
import { Truck, Package, Clock, MapPin, CheckCircle, Wifi, WifiOff, RefreshCw, ShoppingBag } from 'lucide-react'

interface OrderItem {
  name: string
  quantity: number
  shop_name?: string
}

interface Order {
  id: string
  order_number: string
  type: 'SHOPPING' | 'DELIVERY'
  status: string
  pickup_details?: string
  delivery_details?: string
  distance_km?: number
  delivery_fee: number
  created_at: string
  order_items?: OrderItem[]
}

const DEMO_PENDING: Order[] = [
  {
    id: 'demo-1', order_number: 'ORD-1718001-ABCD', type: 'SHOPPING', status: 'PENDING',
    pickup_details: 'برجر تاون - شارع التحرير', delivery_details: 'عمارة 15، شارع النيل',
    distance_km: 2.3, delivery_fee: 25, created_at: new Date(Date.now() - 120000).toISOString(),
    order_items: [{ name: 'وجبة برجر كاملة', quantity: 2, shop_name: 'برجر تاون' }],
  },
  {
    id: 'demo-2', order_number: 'ORD-1718002-EFGH', type: 'DELIVERY', status: 'PENDING',
    pickup_details: 'شارع الهرم، الجيزة', delivery_details: 'مدينة نصر، القاهرة',
    distance_km: 4.7, delivery_fee: 40, created_at: new Date(Date.now() - 45000).toISOString(),
  },
  {
    id: 'demo-3', order_number: 'ORD-1718003-IJKL', type: 'SHOPPING', status: 'PENDING',
    pickup_details: 'كشري الحلوة - شارع الهرم', delivery_details: 'المعادي، القاهرة',
    distance_km: 3.1, delivery_fee: 30, created_at: new Date(Date.now() - 15000).toISOString(),
    order_items: [{ name: 'كيلو كشري', quantity: 1 }],
  },
]

export default function CourierDashboard() {
  const [pendingOrders, setPendingOrders] = useState<Order[]>(DEMO_PENDING)
  const [myOrders, setMyOrders] = useState<Order[]>([])
  const [accepting, setAccepting] = useState<string | null>(null)
  const [isOnline, setIsOnline] = useState(true)
  const [tab, setTab] = useState<'pending' | 'mine'>('pending')
  const [lastRefresh, setLastRefresh] = useState(new Date())

  // Simulate Realtime - طلب جديد كل 15 ثانية للديمو
  useEffect(() => {
    if (!isOnline) return
    const interval = setInterval(() => {
      const hasNew = Math.random() > 0.6
      if (hasNew) {
        const newOrder: Order = {
          id: `demo-${Date.now()}`,
          order_number: `ORD-${Date.now()}-${Math.random().toString(36).substr(2, 4).toUpperCase()}`,
          type: Math.random() > 0.5 ? 'SHOPPING' : 'DELIVERY',
          status: 'PENDING',
          pickup_details: ['بيتزا كينج - التحرير', 'مطعم الشرق - نصر', 'فراخ الجنة - فيصل'][Math.floor(Math.random() * 3)],
          delivery_details: ['الزمالك', 'المهندسين', 'العجوزة', 'الدقي'][Math.floor(Math.random() * 4)],
          distance_km: Math.round(Math.random() * 8 * 10) / 10 + 1,
          delivery_fee: Math.ceil((Math.random() * 4 + 1.5) * 8 / 5) * 5,
          created_at: new Date().toISOString(),
          order_items: Math.random() > 0.5 ? [{ name: 'منتج جديد', quantity: 1 }] : undefined,
        }
        setPendingOrders(prev => [newOrder, ...prev.slice(0, 9)])
        setLastRefresh(new Date())
        toast('🆕 طلب جديد وصل!', { icon: '📦', duration: 3000 })
      }
    }, 15000)
    return () => clearInterval(interval)
  }, [isOnline])

  function acceptOrder(orderId: string) {
    setAccepting(orderId)
    setTimeout(() => {
      const order = pendingOrders.find(o => o.id === orderId)
      if (order) {
        // Race condition simulation: 20% chance someone else took it
        if (Math.random() < 0.2) {
          toast.error('⚡ الأوردر اتحجز من مندوب تاني!')
          setPendingOrders(prev => prev.filter(o => o.id !== orderId))
        } else {
          toast.success('✅ تم قبول الطلب! اتحرك بسرعة 🛵')
          setPendingOrders(prev => prev.filter(o => o.id !== orderId))
          setMyOrders(prev => [{ ...order, status: 'ACCEPTED' }, ...prev])
        }
      }
      setAccepting(null)
    }, 300)
  }

  function updateOrderStatus(orderId: string, status: string) {
    setMyOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o))
    const labels: Record<string, string> = { PICKED_UP: '📦 تم الاستلام', DELIVERED: '✅ تم التوصيل' }
    toast.success(labels[status] || 'تم التحديث')
  }

  const timeSince = (date: string) => {
    const mins = Math.floor((Date.now() - new Date(date).getTime()) / 60000)
    if (mins < 1) return 'الآن'
    if (mins < 60) return `${mins} دقيقة`
    return `${Math.floor(mins / 60)} ساعة`
  }

  const todayEarnings = myOrders
    .filter(o => o.status === 'DELIVERED')
    .reduce((sum, o) => sum + o.delivery_fee, 0)

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black">لوحة المناديب</h1>
          <p className="text-gray-500 text-sm">آخر تحديث: {lastRefresh.toLocaleTimeString('ar-EG')}</p>
        </div>
        <button
          onClick={() => { setIsOnline(!isOnline); toast.success(!isOnline ? '🟢 متاح للطلبات' : '🔴 تم إيقاف الاستقبال') }}
          className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm transition-all ${
            isOnline ? 'bg-green-100 text-green-700 hover:bg-green-200' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
          }`}
        >
          {isOnline ? <Wifi size={16} /> : <WifiOff size={16} />}
          {isOnline ? 'متاح' : 'غير متاح'}
        </button>
      </div>

      {/* Live Indicator */}
      <div className="flex items-center gap-3 bg-green-50 border border-green-200 rounded-xl px-4 py-3">
        <span className="w-2.5 h-2.5 bg-green-500 rounded-full animate-pulse block" />
        <span className="text-green-700 font-bold text-sm">
          {isOnline ? 'متصل - الأوردرات بتظهر لحظياً ⚡' : 'غير متصل - لن تستقبل طلبات'}
        </span>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-orange-500">{pendingOrders.length}</div>
          <div className="text-xs text-gray-500">طلبات جديدة</div>
        </div>
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-blue-500">{myOrders.filter(o => o.status === 'ACCEPTED').length}</div>
          <div className="text-xs text-gray-500">جاري التوصيل</div>
        </div>
        <div className="card text-center py-3">
          <div className="text-2xl font-black text-green-500">{todayEarnings} ج</div>
          <div className="text-xs text-gray-500">أرباح اليوم</div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl">
        <button onClick={() => setTab('pending')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${tab === 'pending' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'}`}>
          طلبات جديدة ({pendingOrders.length})
        </button>
        <button onClick={() => setTab('mine')}
          className={`flex-1 py-2.5 rounded-lg font-bold text-sm transition-all ${tab === 'mine' ? 'bg-white text-orange-600 shadow-sm' : 'text-gray-600'}`}>
          طلباتي ({myOrders.length})
        </button>
      </div>

      {/* Pending Orders */}
      {tab === 'pending' && (
        <div className="space-y-3">
          {!isOnline ? (
            <div className="text-center py-12">
              <WifiOff size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">فعّل "متاح" عشان تشوف الطلبات</p>
            </div>
          ) : pendingOrders.length === 0 ? (
            <div className="text-center py-12">
              <Package size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500 font-semibold">مفيش طلبات جديدة دلوقتي</p>
              <p className="text-gray-400 text-sm">لما يجي طلب هيظهر هنا فوراً</p>
            </div>
          ) : (
            pendingOrders.map(order => (
              <div key={order.id} className="card border-r-4 border-orange-500 order-card-enter">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <div className="w-10 h-10 bg-orange-100 rounded-xl flex items-center justify-center">
                      {order.type === 'SHOPPING' ? <ShoppingBag className="text-orange-500" size={20} /> : <Truck className="text-orange-500" size={20} />}
                    </div>
                    <div>
                      <div className="font-bold text-sm">{order.order_number}</div>
                      <div className="text-xs text-gray-400">منذ {timeSince(order.created_at)}</div>
                    </div>
                  </div>
                  <div className="text-left">
                    <div className="text-orange-600 font-black text-lg">{order.delivery_fee} ج</div>
                    {order.distance_km && <div className="text-xs text-gray-400">{order.distance_km} كم</div>}
                  </div>
                </div>

                {order.order_items && order.order_items.length > 0 && (
                  <div className="mb-3 bg-gray-50 rounded-xl p-3">
                    <div className="text-xs text-gray-500 mb-1 font-semibold">المنتجات:</div>
                    {order.order_items.map((item, i) => (
                      <div key={i} className="text-sm text-gray-700">
                        • {item.name} × {item.quantity}
                        {item.shop_name && <span className="text-gray-400"> ({item.shop_name})</span>}
                      </div>
                    ))}
                  </div>
                )}

                <div className="flex items-center gap-1 text-gray-500 text-sm mb-4">
                  <MapPin size={14} />
                  <span className="truncate">{order.pickup_details} → {order.delivery_details}</span>
                </div>

                <button
                  disabled={accepting === order.id}
                  onClick={() => acceptOrder(order.id)}
                  className="w-full bg-orange-500 hover:bg-orange-600 active:scale-95 text-white font-black py-3 rounded-xl transition-all flex items-center justify-center gap-2 disabled:opacity-50 text-lg shadow-lg"
                >
                  {accepting === order.id ? (
                    <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري القبول...</>
                  ) : (
                    <><CheckCircle size={22} />قبول الطلب ⚡</>
                  )}
                </button>
              </div>
            ))
          )}
        </div>
      )}

      {/* My Orders */}
      {tab === 'mine' && (
        <div className="space-y-3">
          {myOrders.length === 0 ? (
            <div className="text-center py-12">
              <Truck size={48} className="mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">مش عندك طلبات لحد دلوقتي</p>
            </div>
          ) : (
            myOrders.map(order => (
              <div key={order.id} className="card">
                <div className="flex items-center justify-between mb-2">
                  <div className="font-bold text-sm">{order.order_number}</div>
                  <span className={`text-xs font-bold px-2 py-1 rounded-full ${
                    order.status === 'DELIVERED' ? 'bg-green-100 text-green-700' :
                    order.status === 'ACCEPTED' ? 'bg-blue-100 text-blue-700' :
                    'bg-yellow-100 text-yellow-700'
                  }`}>
                    {order.status === 'DELIVERED' ? '✅ تم التوصيل' : order.status === 'ACCEPTED' ? '🛵 مقبول' : order.status === 'PICKED_UP' ? '📦 تم الاستلام' : order.status}
                  </span>
                </div>
                <div className="text-orange-600 font-bold text-sm mb-3">{order.delivery_fee} جنيه</div>
                {order.status === 'ACCEPTED' && (
                  <button onClick={() => updateOrderStatus(order.id, 'PICKED_UP')}
                    className="w-full btn-primary text-sm py-2">📦 تأكيد الاستلام</button>
                )}
                {order.status === 'PICKED_UP' && (
                  <button onClick={() => updateOrderStatus(order.id, 'DELIVERED')}
                    className="w-full bg-green-500 hover:bg-green-600 text-white font-bold py-2 rounded-xl text-sm">✅ تأكيد التوصيل</button>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  )
}

import { useState, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { User, Phone, MapPin, CreditCard, Upload, CheckCircle, ArrowLeft } from 'lucide-react'

type Step = 'info' | 'id-upload' | 'review'

export default function CourierRegister() {
  const navigate = useNavigate()
  const [step, setStep] = useState<Step>('info')
  const [submitting, setSubmitting] = useState(false)
  const [name, setName] = useState('')
  const [phone, setPhone] = useState('')
  const [address, setAddress] = useState('')
  const [frontFile, setFrontFile] = useState<File | null>(null)
  const [backFile, setBackFile] = useState<File | null>(null)
  const [frontPreview, setFrontPreview] = useState<string | null>(null)
  const [backPreview, setBackPreview] = useState<string | null>(null)
  const frontRef = useRef<HTMLInputElement>(null)
  const backRef = useRef<HTMLInputElement>(null)

  function handleFileChange(file: File | null, setFile: (f: File | null) => void, setPreview: (s: string | null) => void) {
    if (!file) return
    if (file.size > 5 * 1024 * 1024) { toast.error('حجم الصورة أكبر من 5MB'); return }
    if (!['image/jpeg', 'image/png', 'image/webp'].includes(file.type)) { toast.error('نوع الملف غير مدعوم'); return }
    setFile(file)
    const reader = new FileReader()
    reader.onload = e => setPreview(e.target?.result as string)
    reader.readAsDataURL(file)
  }

  function validateInfo() {
    if (!name.trim() || name.length < 3) { toast.error('الاسم لازم يكون 3 حروف على الأقل'); return false }
    if (!/^01[0-9]{9}$/.test(phone)) { toast.error('رقم الموبايل غير صحيح (مثال: 01012345678)'); return false }
    if (!address.trim() || address.length < 10) { toast.error('العنوان لازم يكون أكتر من 10 حروف'); return false }
    return true
  }

  function uploadImages() {
    if (!frontFile || !backFile) { toast.error('ارفع صورة وجه وضهر البطاقة'); return }
    setSubmitting(true)
    setTimeout(() => { setStep('review'); setSubmitting(false); toast.success('تم رفع الصور') }, 1000)
  }

  function submitRegistration() {
    setSubmitting(true)
    setTimeout(() => {
      toast.success('🎉 تم التسجيل! بياناتك تحت المراجعة خلال 24 ساعة')
      navigate('/courier/dashboard')
      setSubmitting(false)
    }, 1500)
  }

  return (
    <div className="max-w-lg mx-auto space-y-6">
      <div>
        <h1 className="text-2xl font-black">انضم كمندوب 🛵</h1>
        <p className="text-gray-500 text-sm mt-1">اكسب فلوس وانت بتوصل الطلبات</p>
      </div>

      {/* Progress */}
      <div className="flex items-center gap-2">
        {[{ key: 'info', label: 'البيانات', num: 1 }, { key: 'id-upload', label: 'البطاقة', num: 2 }, { key: 'review', label: 'مراجعة', num: 3 }].map((s, i) => (
          <div key={s.key} className="flex items-center gap-2 flex-1">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold transition-all ${
              step === s.key ? 'bg-orange-500 text-white' :
              ['info', 'id-upload', 'review'].indexOf(step) > i ? 'bg-green-500 text-white' :
              'bg-gray-200 text-gray-500'
            }`}>
              {['info', 'id-upload', 'review'].indexOf(step) > i ? '✓' : s.num}
            </div>
            <span className="text-xs text-gray-500 hidden sm:block">{s.label}</span>
            {i < 2 && <div className={`flex-1 h-1 rounded-full ${['info', 'id-upload', 'review'].indexOf(step) > i ? 'bg-green-400' : 'bg-gray-200'}`} />}
          </div>
        ))}
      </div>

      {/* Step 1 */}
      {step === 'info' && (
        <div className="space-y-4 animate-fade-in">
          <div className="card space-y-4">
            <h2 className="font-bold text-lg flex items-center gap-2"><User className="text-orange-500" size={20} />البيانات الشخصية</h2>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">الاسم الكامل *</label>
              <input className="input" placeholder="محمد أحمد" value={name} onChange={e => setName(e.target.value)} />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2">رقم الموبايل * <span className="text-xs text-orange-500">(بصمتك الفريدة - لا يتكرر)</span></label>
              <input className="input" placeholder="01012345678" value={phone} onChange={e => setPhone(e.target.value.replace(/[^0-9]/g, ''))} maxLength={11} dir="ltr" />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-600 mb-2"><MapPin className="inline" size={14} /> عنوانك بالتفصيل *</label>
              <textarea className="input resize-none h-20" placeholder="رقم الشارع، الحي، المدينة..." value={address} onChange={e => setAddress(e.target.value)} />
            </div>
          </div>
          <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 text-sm text-blue-700">
            <strong>🔒 أمان كامل:</strong> صور البطاقة محمية بـ Signed URLs صالحة 5 دقائق فقط.
          </div>
          <button onClick={() => { if (validateInfo()) setStep('id-upload') }} className="btn-primary w-full">
            التالي - رفع البطاقة
          </button>
        </div>
      )}

      {/* Step 2 */}
      {step === 'id-upload' && (
        <div className="space-y-4 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('info')} className="p-2 hover:bg-gray-100 rounded-xl"><ArrowLeft size={20} /></button>
            <h2 className="font-bold text-lg flex items-center gap-2"><CreditCard className="text-orange-500" size={20} />صور البطاقة الشخصية</h2>
          </div>
          {[
            { label: 'وجه البطاقة (الصورة) *', ref: frontRef, file: frontFile, preview: frontPreview, setFile: setFrontFile, setPreview: setFrontPreview },
            { label: 'ضهر البطاقة *', ref: backRef, file: backFile, preview: backPreview, setFile: setBackFile, setPreview: setBackPreview },
          ].map((img, i) => (
            <div key={i} onClick={() => img.ref.current?.click()}
              className={`border-2 border-dashed rounded-2xl p-6 text-center cursor-pointer transition-all ${img.preview ? 'border-green-400 bg-green-50' : 'border-gray-300 hover:border-orange-400 hover:bg-orange-50'}`}>
              <input ref={img.ref} type="file" accept="image/*" className="hidden"
                onChange={e => handleFileChange(e.target.files?.[0] || null, img.setFile, img.setPreview)} />
              {img.preview ? (
                <div>
                  <img src={img.preview} alt={img.label} className="h-32 mx-auto rounded-xl object-cover mb-2" />
                  <p className="text-green-600 font-bold text-sm">✅ {img.label.replace(' *', '')}</p>
                </div>
              ) : (
                <div>
                  <Upload className="mx-auto mb-3 text-gray-400" size={32} />
                  <p className="font-bold text-gray-700">{img.label}</p>
                  <p className="text-xs text-gray-400 mt-1">JPG, PNG حتى 5MB</p>
                </div>
              )}
            </div>
          ))}
          <button disabled={submitting || !frontFile || !backFile} onClick={uploadImages}
            className="btn-primary w-full flex items-center justify-center gap-2">
            {submitting ? <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري الرفع...</> : <><Upload size={20} />رفع الصور والمتابعة</>}
          </button>
        </div>
      )}

      {/* Step 3 */}
      {step === 'review' && (
        <div className="space-y-4 animate-fade-in">
          <div className="flex items-center gap-3">
            <button onClick={() => setStep('id-upload')} className="p-2 hover:bg-gray-100 rounded-xl"><ArrowLeft size={20} /></button>
            <h2 className="font-bold text-lg">مراجعة البيانات ✅</h2>
          </div>
          <div className="card space-y-3">
            {[
              { label: 'الاسم', value: name },
              { label: 'الموبايل', value: phone },
              { label: 'العنوان', value: address },
              { label: 'وجه البطاقة', value: '✅ مرفوع' },
              { label: 'ضهر البطاقة', value: '✅ مرفوع' },
            ].map(item => (
              <div key={item.label} className="flex justify-between text-sm border-b border-gray-100 pb-2">
                <span className="text-gray-500">{item.label}</span>
                <span className="font-semibold">{item.value}</span>
              </div>
            ))}
          </div>
          <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 text-sm text-yellow-800">
            <strong>⏳ بعد التسجيل:</strong> بياناتك هتتراجع خلال 24 ساعة. لو اتوافق هتبدأ تستقبل طلبات.
          </div>
          <button disabled={submitting} onClick={submitRegistration}
            className="btn-primary w-full flex items-center justify-center gap-2 text-lg">
            {submitting ? <><div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent" />جاري التسجيل...</> : <><CheckCircle size={22} />تأكيد التسجيل</>}
          </button>
        </div>
      )}
    </div>
  )
}

