import { createContext, useContext, useState, ReactNode } from 'react'

export type UserRole = 'client' | 'courier' | 'admin' | null

export interface DemoUser {
  id: string
  name: string
  phone: string
  role: UserRole
  avatar: string
}

interface AuthContextType {
  user: DemoUser | null
  login: (role: UserRole) => void
  logout: () => void
  isLoggedIn: boolean
}

const DEMO_USERS: Record<NonNullable<UserRole>, DemoUser> = {
  client: { id: 'client-1', name: 'أحمد العميل', phone: '01012345678', role: 'client', avatar: '👤' },
  courier: { id: 'courier-1', name: 'محمد المندوب', phone: '01098765432', role: 'courier', avatar: '🛵' },
  admin: { id: 'admin-1', name: 'أدمن المنصة', phone: '01111111111', role: 'admin', avatar: '🛡️' },
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  login: () => {},
  logout: () => {},
  isLoggedIn: false,
})

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<DemoUser | null>(() => {
    const saved = localStorage.getItem('mandoubak_user')
    return saved ? JSON.parse(saved) : null
  })

  function login(role: UserRole) {
    if (!role) return
    const demoUser = DEMO_USERS[role]
    setUser(demoUser)
    localStorage.setItem('mandoubak_user', JSON.stringify(demoUser))
  }

  function logout() {
    setUser(null)
    localStorage.removeItem('mandoubak_user')
  }

  return (
    <AuthContext.Provider value={{ user, login, logout, isLoggedIn: !!user }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => useContext(AuthContext)

import { createContext, useContext, useState, ReactNode } from 'react'

export interface Notification {
  id: string
  title: string
  message: string
  type: 'order' | 'courier' | 'system' | 'success'
  read: boolean
  createdAt: Date
  icon?: string
}

interface NotificationsContextType {
  notifications: Notification[]
  unreadCount: number
  addNotification: (n: Omit<Notification, 'id' | 'read' | 'createdAt'>) => void
  markAllRead: () => void
  markRead: (id: string) => void
}

const NotificationsContext = createContext<NotificationsContextType>({
  notifications: [],
  unreadCount: 0,
  addNotification: () => {},
  markAllRead: () => {},
  markRead: () => {},
})

const DEMO_NOTIFICATIONS: Notification[] = [
  { id: '1', title: 'طلبك قيد التوصيل 🛵', message: 'محمد المندوب في طريقه إليك - ETA 15 دقيقة', type: 'order', read: false, createdAt: new Date(Date.now() - 300000), icon: '🛵' },
