  { id: '3', title: 'عرض جديد 🔥', message: 'بيتزا مارجريتا بـ 89 جنيه - عرض لليوم فقط!', type: 'system', read: true, createdAt: new Date(Date.now() - 3600000), icon: '🍕' },
