  const { unreadCount } = useNotifications()
  const [menuOpen, setMenuOpen] = useState(false)
  const [userDropdown, setUserDropdown] = useState(false)
  const dropdownRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    function handler(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setUserDropdown(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  const isActive = (path: string) => path === '/' ? location.pathname === '/' : location.pathname.startsWith(path)

  const navLinks = [
    { to: '/', icon: <Home size={18} />, label: 'الرئيسية' },
    { to: '/order', icon: <Package size={18} />, label: 'اطلب الآن' },
    { to: '/courier/dashboard', icon: <Truck size={18} />, label: 'المناديب' },
    { to: '/admin', icon: <ShieldCheck size={18} />, label: 'الأدمن' },
  ]

  const ROLE_COLORS: Record<string, string> = {
    client: 'bg-blue-500',
    courier: 'bg-orange-500',
    admin: 'bg-purple-500',
  }
  const ROLE_LABELS: Record<string, string> = {
    client: 'عميل',
    courier: 'مندوب',
    admin: 'أدمن',
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-16 md:pb-0">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-40 shadow-sm">
        <div className="max-w-6xl mx-auto px-4">
          <div className="flex items-center justify-between h-15 py-2.5">
            {/* Logo */}
            <Link to="/" className="flex items-center gap-2 flex-shrink-0">
              <div className="w-9 h-9 bg-orange-500 rounded-xl flex items-center justify-center shadow-md shadow-orange-200">
                <Truck className="text-white" size={20} />
              </div>
              <span className="text-xl font-black text-gray-900">مندوبك</span>
            </Link>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center gap-0.5">
              {navLinks.map(link => (
                <Link
                  key={link.to}
                  to={link.to}
                  className={`flex items-center gap-1.5 px-3.5 py-2 rounded-xl text-sm font-semibold transition-all ${
                    isActive(link.to)
                      ? 'bg-orange-50 text-orange-600'
                      : 'text-gray-600 hover:bg-gray-100'
                  }`}
                >
                  {link.icon}
                  {link.label}
                </Link>
              ))}
            </div>

            {/* Right side */}
            <div className="flex items-center gap-2">
              {/* Notifications */}
              <Link to="/notifications" className="relative p-2 rounded-xl hover:bg-gray-100 transition-colors">
                <Bell size={20} className={unreadCount > 0 ? 'text-orange-500' : 'text-gray-600'} />
                {unreadCount > 0 && (
                  <span className="absolute top-1 left-1 w-4 h-4 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">
                    {unreadCount > 9 ? '9+' : unreadCount}
                  </span>
                )}
              </Link>

              {/* User Menu */}
              {user ? (
                <div className="relative" ref={dropdownRef}>
                  <button
                    onClick={() => setUserDropdown(!userDropdown)}
                    className="hidden md:flex items-center gap-2 pl-3 pr-2 py-1.5 rounded-xl hover:bg-gray-100 transition-colors"
                  >
                    <div className={`w-7 h-7 ${ROLE_COLORS[user.role!]} rounded-lg flex items-center justify-center text-white text-xs font-black`}>
                      {user.name[0]}
                    </div>
                    <div className="text-right">
                      <div className="text-sm font-bold text-gray-900 leading-tight">{user.name.split(' ')[0]}</div>
                      <div className="text-xs text-gray-500">{ROLE_LABELS[user.role!]}</div>
                    </div>
                    <ChevronDown size={14} className={`text-gray-400 transition-transform ${userDropdown ? 'rotate-180' : ''}`} />
                  </button>

                  {userDropdown && (
                    <div className="absolute top-full left-0 mt-2 w-48 bg-white rounded-2xl shadow-xl border border-gray-100 py-2 animate-fade-in">
                      {user.role === 'client' && (
                        <Link to="/my-orders" onClick={() => setUserDropdown(false)}
                          className="flex items-center gap-2 px-4 py-2.5 text-sm hover:bg-gray-50 transition-colors">
                          <Package size={16} className="text-orange-500" /> طلباتي
                        </Link>
                      )}
                      {user.role === 'courier' && (
                        <Link to="/courier/profile" onClick={() => setUserDropdown(false)}
                          className="flex items-center gap-2 px-4 py-2.5 text-sm hover:bg-gray-50 transition-colors">
                          <User size={16} className="text-blue-500" /> بروفايلي
                        </Link>
                      )}
                      <Link to="/login" onClick={() => setUserDropdown(false)}
                        className="flex items-center gap-2 px-4 py-2.5 text-sm hover:bg-gray-50 transition-colors">
                        <User size={16} className="text-purple-500" /> تغيير الدور
                      </Link>
                      <div className="border-t border-gray-100 my-1" />
                      <button
                        onClick={() => { logout(); setUserDropdown(false); navigate('/login') }}
                        className="w-full flex items-center gap-2 px-4 py-2.5 text-sm text-red-500 hover:bg-red-50 transition-colors"
                      >
                        <LogOut size={16} /> خروج
                      </button>
                    </div>
                  )}
                </div>
              ) : (
                <Link to="/login"
                  className="hidden md:flex items-center gap-1.5 bg-orange-500 hover:bg-orange-600 text-white font-bold px-4 py-2 rounded-xl text-sm transition-all shadow-md shadow-orange-200">
                  <LogIn size={16} />
                  دخول
                </Link>
              )}

              {/* Mobile menu button */}
              <button
                onClick={() => setMenuOpen(!menuOpen)}
                className="md:hidden p-2 rounded-xl hover:bg-gray-100 transition-colors"
              >
                {menuOpen ? <X size={22} /> : <Menu size={22} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {menuOpen && (
          <div className="md:hidden border-t border-gray-100 bg-white px-4 py-3 space-y-1 animate-fade-in">
            {navLinks.map(link => (
              <Link
                key={link.to}
                to={link.to}
                onClick={() => setMenuOpen(false)}
                className={`flex items-center gap-2 px-4 py-3 rounded-xl text-sm font-semibold transition-all ${
                  isActive(link.to)
                    ? 'bg-orange-50 text-orange-600'
                    : 'text-gray-600 hover:bg-gray-50'
                }`}
              >
                {link.icon}
                {link.label}
              </Link>
            ))}
            {user ? (
              <div className="border-t border-gray-100 pt-2 mt-2 space-y-1">
                <div className="flex items-center gap-3 px-4 py-2">
                  <div className={`w-9 h-9 ${ROLE_COLORS[user.role!]} rounded-xl flex items-center justify-center text-white font-black`}>
                    {user.name[0]}
                  </div>
                  <div>
                    <div className="font-bold text-sm">{user.name}</div>
                    <div className="text-xs text-gray-500">{ROLE_LABELS[user.role!]}</div>
                  </div>
                </div>
                <button onClick={() => { logout(); navigate('/login'); setMenuOpen(false) }}
                  className="w-full flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm text-red-500 hover:bg-red-50">
                  <LogOut size={16} /> خروج
                </button>
              </div>
            ) : (
              <Link to="/login" onClick={() => setMenuOpen(false)}
                className="flex items-center gap-2 px-4 py-3 bg-orange-500 text-white font-bold rounded-xl text-sm mt-2">
                <LogIn size={16} /> دخول للتطبيق
              </Link>
            )}
          </div>
        )}
      </nav>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-5">
        <Outlet />
      </main>

      {/* Bottom Nav - Mobile Only */}
      <BottomNav />
    </div>
  )
}

import { useState } from 'react'
import { User, Phone, MapPin, Package, Star, Edit3, Save, X, LogOut } from 'lucide-react'
import { useAuth } from '../lib/auth-context'
import { useNavigate, Link } from 'react-router-dom'
import toast from 'react-hot-toast'

export default function ClientProfile() {
  const { user, logout } = useAuth()
  const navigate = useNavigate()
  const [editing, setEditing] = useState(false)
  const [name, setName] = useState(user?.name || 'أحمد العميل')
  const [phone, setPhone] = useState(user?.phone || '01012345678')
  const [address, setAddress] = useState('شارع النيل، الزمالك، القاهرة')

  function saveProfile() {
    toast.success('تم حفظ البيانات ✅')
    setEditing(false)
  }

  const DEMO_STATS = [
    { label: 'إجمالي الطلبات', value: 24, icon: '📦' },
    { label: 'إجمالي الإنفاق', value: '680 ج', icon: '💰' },
    { label: 'متوسط سعر التوصيل', value: '28 ج', icon: '🛵' },
    { label: 'مناديب مفضلين', value: 3, icon: '⭐' },
  ]

  const RECENT_COURIERS = [
    { name: 'محمد علي', rating: 4.8, trips: 5, avatar: 'م' },
    { name: 'خالد حسن', rating: 4.6, trips: 3, avatar: 'خ' },
    { name: 'أحمد سمير', rating: 4.9, trips: 2, avatar: 'أ' },
  ]

  return (
    <div className="max-w-lg mx-auto space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-black">حسابي</h1>
        <button onClick={() => setEditing(!editing)}
          className={`flex items-center gap-1.5 text-sm font-bold px-3 py-2 rounded-xl transition-all ${editing ? 'bg-red-50 text-red-500' : 'bg-orange-50 text-orange-600'}`}>
          {editing ? <><X size={16} /> إلغاء</> : <><Edit3 size={16} /> تعديل</>}
        </button>
      </div>

      {/* Avatar & Name */}
      <div className="card text-center">
        <div className="w-20 h-20 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-3 text-3xl font-black text-blue-600">
          {name[0]}
        </div>
        {editing ? (
          <input className="input text-center text-lg font-bold mb-2" value={name} onChange={e => setName(e.target.value)} />
        ) : (
          <h2 className="text-xl font-black">{name}</h2>
        )}
        <div className="inline-flex items-center gap-1 bg-blue-100 text-blue-600 text-xs font-bold px-3 py-1 rounded-full mt-1">
          👤 عميل
        </div>
      </div>

      {/* Info */}
      <div className="card space-y-4">
        <h3 className="font-bold text-gray-600 text-sm">بياناتي</h3>
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <Phone size={16} className="text-orange-500 flex-shrink-0" />
            {editing ? (
              <input className="input flex-1 text-sm" value={phone} onChange={e => setPhone(e.target.value)} dir="ltr" />
            ) : (
              <span className="text-sm font-semibold">{phone}</span>
            )}
          </div>
          <div className="flex items-start gap-3">
            <MapPin size={16} className="text-orange-500 flex-shrink-0 mt-0.5" />
            {editing ? (
              <input className="input flex-1 text-sm" value={address} onChange={e => setAddress(e.target.value)} />
            ) : (
              <span className="text-sm font-semibold">{address}</span>
            )}
          </div>
        </div>
        {editing && (
          <button onClick={saveProfile} className="btn-primary w-full flex items-center justify-center gap-2">
            <Save size={18} /> حفظ التغييرات
          </button>
        )}
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 gap-3">
        {DEMO_STATS.map((stat, i) => (
          <div key={i} className="card text-center py-4">
            <div className="text-2xl mb-1">{stat.icon}</div>
            <div className="text-lg font-black">{stat.value}</div>
            <div className="text-xs text-gray-500">{stat.label}</div>
          </div>
        ))}
      </div>

      {/* Recent Couriers */}
      <div className="card">
        <h3 className="font-bold mb-4">🛵 أكتر المناديب معك</h3>
        <div className="space-y-3">
          {RECENT_COURIERS.map((c, i) => (
            <div key={i} className="flex items-center gap-3">
              <div className="w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center font-bold text-orange-600">
                {c.avatar}
              </div>
              <div className="flex-1">
                <div className="font-bold text-sm">{c.name}</div>
                <div className="text-xs text-gray-400">{c.trips} طلبات معك</div>
              </div>
              <div className="flex items-center gap-1 text-sm">
                <Star size={13} className="text-yellow-400 fill-yellow-400" />
                <span className="font-semibold">{c.rating}</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-2 gap-3">
        <Link to="/my-orders" className="card flex items-center gap-3 hover:shadow-md transition-all">
          <Package className="text-orange-500" size={22} />
          <div>
            <div className="font-bold text-sm">طلباتي</div>
            <div className="text-xs text-gray-400">سجل كامل</div>
          </div>
        </Link>
        <Link to="/order" className="card flex items-center gap-3 hover:shadow-md transition-all">
          <span className="text-2xl">+</span>
          <div>
            <div className="font-bold text-sm">طلب جديد</div>
            <div className="text-xs text-gray-400">اطلب دلوقتي</div>
          </div>
        </Link>
      </div>

      {/* Logout */}
      <button onClick={() => { logout(); navigate('/login'); toast.success('تم الخروج 👋') }}
        className="w-full flex items-center justify-center gap-2 py-3 text-red-500 hover:bg-red-50 rounded-2xl font-bold transition-all">
        <LogOut size={18} />
        خروج
      </button>
    </div>
  )
}

import { Link, useLocation } from 'react-router-dom'
import { Home, Package, Bell, User, Truck, DollarSign, ShieldCheck } from 'lucide-react'
import { useNotifications } from '../lib/notifications-context'
import { useAuth } from '../lib/auth-context'

export default function BottomNav() {
  const location = useLocation()
  const { unreadCount } = useNotifications()
  const { user } = useAuth()
  const path = location.pathname

  const isActive = (to: string) => to === '/' ? path === '/' : path.startsWith(to)

  // Different nav based on role
  const clientNav = [
    { to: '/', icon: <Home size={22} />, label: 'الرئيسية' },
    { to: '/order', icon: <Package size={22} />, label: 'اطلب' },
    { to: '/my-orders', icon: <Truck size={22} />, label: 'طلباتي' },
    {
      to: '/notifications', label: 'إشعارات',
      icon: <div className="relative"><Bell size={22} />{unreadCount > 0 && <span className="absolute -top-2 -left-2 w-4 h-4 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">{unreadCount > 9 ? '9+' : unreadCount}</span>}</div>
    },
    { to: '/profile', icon: <User size={22} />, label: 'حسابي' },
  ]

  const courierNav = [
    { to: '/', icon: <Home size={22} />, label: 'الرئيسية' },
    { to: '/courier/dashboard', icon: <Truck size={22} />, label: 'الطلبات' },
    { to: '/courier/earnings', icon: <DollarSign size={22} />, label: 'أرباحي' },
    {
      to: '/notifications', label: 'إشعارات',
      icon: <div className="relative"><Bell size={22} />{unreadCount > 0 && <span className="absolute -top-2 -left-2 w-4 h-4 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">{unreadCount > 9 ? '9+' : unreadCount}</span>}</div>
    },
    { to: '/courier/profile', icon: <User size={22} />, label: 'بروفايلي' },
  ]

  const adminNav = [
    { to: '/', icon: <Home size={22} />, label: 'الرئيسية' },
    { to: '/admin', icon: <ShieldCheck size={22} />, label: 'لوحة القيادة' },
    { to: '/admin/couriers', icon: <Truck size={22} />, label: 'المناديب' },
    { to: '/admin/ads', icon: <Package size={22} />, label: 'الإعلانات' },
    {
      to: '/notifications', label: 'إشعارات',
      icon: <div className="relative"><Bell size={22} />{unreadCount > 0 && <span className="absolute -top-2 -left-2 w-4 h-4 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">{unreadCount > 9 ? '9+' : unreadCount}</span>}</div>
    },
  ]

  const guestNav = [
    { to: '/', icon: <Home size={22} />, label: 'الرئيسية' },
    { to: '/order', icon: <Package size={22} />, label: 'اطلب' },
    {
      to: '/notifications', label: 'إشعارات',
      icon: <div className="relative"><Bell size={22} />{unreadCount > 0 && <span className="absolute -top-2 -left-2 w-4 h-4 bg-red-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">{unreadCount > 9 ? '9+' : unreadCount}</span>}</div>
    },
    { to: '/login', icon: <User size={22} />, label: 'دخول' },
  ]

  const navItems = user?.role === 'courier' ? courierNav
    : user?.role === 'admin' ? adminNav
    : user?.role === 'client' ? clientNav
    : guestNav

  return (
    <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-gray-200 md:hidden">
      <div className="flex">
        {navItems.map((item, i) => {
          const active = isActive(item.to)
          return (
            <Link key={i} to={item.to}
              className={`flex-1 flex flex-col items-center pt-2.5 pb-3 px-1 transition-all ${active ? 'text-orange-500' : 'text-gray-400'}`}>
              <div className={`transition-all ${active ? 'scale-110' : 'scale-100'}`}>
                {item.icon}
              </div>
              <span className={`text-[10px] mt-1 font-bold truncate max-w-full text-center ${active ? 'text-orange-500' : 'text-gray-400'}`}>
                {item.label}
              </span>
              {active && <div className="w-6 h-0.5 bg-orange-500 rounded-full mt-1" />}
            </Link>
          )
        })}
      </div>
    </nav>
  )
}

