    body = await c.req.json()
  } catch {
    return c.json({ error: 'بيانات غير صحيحة' }, 400)
  }

  const schema = z.object({
    status: z.enum(['APPROVED', 'REJECTED', 'SUSPENDED']),
    reason: z.string().max(500).optional(),
  })

  const parsed = schema.safeParse(body)
