// =============================================================
// Upload API - رفع صور البطايق على R2
// POST /api/upload/id      - رفع صور البطاقة
// POST /api/upload/product - رفع صورة منتج
// GET  /api/upload/view    - عرض صورة بـ Signed URL
// GET  /api/upload/signed  - إنشاء Signed URL
// =============================================================

import { Hono } from 'hono'
import type { Env } from '../index'
import { authMiddleware } from '../middleware/auth'
import { uploadImageToR2, validateImage, createSignedUrl, verifySignedToken } from '../lib/r2'

export const uploadRouter = new Hono<{ Bindings: Env }>()

// All upload routes require auth
uploadRouter.use('*', authMiddleware)

// Max file size: 5MB
const MAX_SIZE_BYTES = 5 * 1024 * 1024
const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'image/webp']

// =====================
// POST /api/upload/id - رفع صور البطاقة (وجه وضهر)
// =====================
uploadRouter.post('/id', async (c) => {
  const user = c.get('user')

  let formData: FormData
  try {
    formData = await c.req.formData()
  } catch {
    return c.json({ error: 'بيانات FormData غير صحيحة' }, 400)
  }

  const frontFile = formData.get('front') as File | null
  const backFile = formData.get('back') as File | null

  if (!frontFile || !backFile) {
    return c.json({ error: 'لازم ترفع صورة الوجه والضهر' }, 400)
  }

  // Validate file types
  for (const [label, file] of [['وجه البطاقة', frontFile], ['ضهر البطاقة', backFile]] as [string, File][]) {
    if (!ALLOWED_TYPES.includes(file.type)) {
      return c.json({ error: `${label}: نوع الملف غير مدعوم - JPG/PNG/WebP بس` }, 400)
    }
    if (file.size > MAX_SIZE_BYTES) {
      return c.json({ error: `${label}: الصورة أكبر من 5MB` }, 400)
    }
    if (file.size === 0) {
      return c.json({ error: `${label}: الملف فاضي` }, 400)
    }
  }

  const frontValidation = validateImage(frontFile.size, frontFile.type)
  if (!frontValidation.valid) {
    return c.json({ error: `صورة الوجه: ${frontValidation.error}` }, 400)
  }

  const backValidation = validateImage(backFile.size, backFile.type)
  if (!backValidation.valid) {
    return c.json({ error: `صورة الضهر: ${backValidation.error}` }, 400)
  }

  try {
    const frontBuffer = await frontFile.arrayBuffer()
    const backBuffer = await backFile.arrayBuffer()

    // رفع الصورتين بالتوازي
    const [frontResult, backResult] = await Promise.all([
      uploadImageToR2(
        c.env.MANDOUBAK_R2,
        frontBuffer,
        user.userId,
        'id_front',
        frontFile.type
      ),
      uploadImageToR2(
        c.env.MANDOUBAK_R2,
        backBuffer,
        user.userId,
        'id_back',
        backFile.type
      )
    ])

    return c.json({
      success: true,
      message: 'تم رفع الصور بنجاح',
      keys: {
        front: frontResult.key,
        back: backResult.key,
      }
    })

  } catch (err) {
    console.error('Upload error:', err)
    return c.json({ error: 'مقدرناش نرفع الصور، جرب تاني' }, 500)
  }
})

// =====================
// POST /api/upload/product - رفع صورة منتج أو إعلان
// =====================
uploadRouter.post('/product', async (c) => {
  const user = c.get('user')

  // Only admins can upload product images
  if (user.role !== 'ADMIN') {
    return c.json({ error: 'مش عندك صلاحية' }, 403)
  }

  let formData: FormData
  try {
    formData = await c.req.formData()
  } catch {
    return c.json({ error: 'بيانات FormData غير صحيحة' }, 400)
  }

  const imageFile = formData.get('image') as File | null

  if (!imageFile) {
    return c.json({ error: 'لازم ترفع صورة' }, 400)
  }

  if (!ALLOWED_TYPES.includes(imageFile.type)) {
    return c.json({ error: 'نوع الملف غير مدعوم - JPG/PNG/WebP بس' }, 400)
  }

  if (imageFile.size > MAX_SIZE_BYTES) {
    return c.json({ error: 'الصورة أكبر من 5MB' }, 400)
  }

  const validation = validateImage(imageFile.size, imageFile.type)
  if (!validation.valid) {
    return c.json({ error: validation.error }, 400)
  }

  try {
    const buffer = await imageFile.arrayBuffer()
    const result = await uploadImageToR2(
      c.env.MANDOUBAK_R2,
      buffer,
      user.userId,
      'product',
      imageFile.type
    )

    return c.json({
      success: true,
      key: result.key,
      url: `/api/upload/view?key=${encodeURIComponent(result.key)}`
    })
  } catch (err) {
    console.error('Product upload error:', err)
    return c.json({ error: 'مقدرناش نرفع الصورة' }, 500)
  }
})

// =====================
// GET /api/upload/view?key=&token= - عرض صورة بـ Signed URL
// الـ link صالح 5 دقايق بس
// =====================
uploadRouter.get('/view', async (c) => {
  const user = c.get('user')
  const key = c.req.query('key')
  const token = c.req.query('token')

  if (!key || !token) {
    return c.json({ error: 'بيانات ناقصة' }, 400)
  }

  // Prevent path traversal
  const decodedKey = decodeURIComponent(key)
  if (decodedKey.includes('..') || decodedKey.startsWith('/')) {
    return c.json({ error: 'مسار غير صحيح' }, 400)
  }

  // Verify the user owns this file (unless admin)
  if (user.role !== 'ADMIN' && !decodedKey.includes(user.userId)) {
    return c.json({ error: 'مش عندك صلاحية لهذه الصورة' }, 403)
  }

  const verification = verifySignedToken(token, decodedKey)
  if (!verification.valid) {
    return c.json({ error: verification.reason || 'لينك منتهي الصلاحية' }, 403)
  }

  try {
    const object = await c.env.MANDOUBAK_R2.get(decodedKey)

    if (!object) {
      return c.json({ error: 'الصورة مش موجودة' }, 404)
    }

    const headers = new Headers()
    headers.set('Content-Type', object.httpMetadata?.contentType || 'image/jpeg')
    headers.set('Cache-Control', 'private, max-age=300, no-store')
    headers.set('Content-Disposition', 'inline')
    headers.set('X-Content-Type-Options', 'nosniff')

    return new Response(object.body, { headers })
  } catch (err) {
    return c.json({ error: 'مقدرناش نجيب الصورة' }, 500)
  }
})

// =====================
// GET /api/upload/signed/:key - إنشاء Signed URL جديد
// =====================
uploadRouter.get('/signed/:key', async (c) => {
  const user = c.get('user')
  const key = decodeURIComponent(c.req.param('key'))

  // Prevent path traversal
  if (key.includes('..') || key.startsWith('/')) {
    return c.json({ error: 'مسار غير صحيح' }, 400)
  }

  // التحقق إن الصورة ملك اليوزر أو الأدمن
  if (!key.includes(user.userId) && user.role !== 'ADMIN') {
    return c.json({ error: 'مش عندك صلاحية' }, 403)
  }

  const signedUrl = await createSignedUrl(c.env.MANDOUBAK_R2, key, 300)

  return c.json({
    success: true,
    url: signedUrl,
    expiresIn: 300,
    expiresAt: new Date(Date.now() + 300 * 1000).toISOString()
  })
})

-- =============================================================
-- مندوبك - Supabase RLS Policies + Security Functions
-- انسخ الكود ده وشغله في Supabase SQL Editor
-- =============================================================

-- تفعيل RLS على كل الجداول
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
ALTER TABLE couriers ENABLE ROW LEVEL SECURITY;
ALTER TABLE customers ENABLE ROW LEVEL SECURITY;
ALTER TABLE addresses ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE order_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE admin_pricing ENABLE ROW LEVEL SECURITY;
ALTER TABLE ad_offers ENABLE ROW LEVEL SECURITY;
ALTER TABLE courier_ratings ENABLE ROW LEVEL SECURITY;

-- Helper function: جيب role اليوزر الحالي
CREATE OR REPLACE FUNCTION get_user_role()
RETURNS TEXT AS $$
  SELECT role FROM users WHERE clerk_id = auth.uid()::text LIMIT 1;
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- Helper function: جيب id اليوزر الحالي
CREATE OR REPLACE FUNCTION get_current_user_id()
RETURNS TEXT AS $$
  SELECT id FROM users WHERE clerk_id = auth.uid()::text LIMIT 1;
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- Helper function: جيب courier_id اليوزر الحالي
CREATE OR REPLACE FUNCTION get_current_courier_id()
RETURNS TEXT AS $$
  SELECT c.id FROM couriers c
  JOIN users u ON u.id = c.user_id
  WHERE u.clerk_id = auth.uid()::text LIMIT 1;
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- =============================================================
-- جدول users
-- =============================================================
DROP POLICY IF EXISTS "users_select_own" ON users;
CREATE POLICY "users_select_own" ON users
  FOR SELECT USING (
    clerk_id = auth.uid()::text
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "users_update_own" ON users;
CREATE POLICY "users_update_own" ON users
  FOR UPDATE USING (clerk_id = auth.uid()::text)
  WITH CHECK (
    -- منع اليوزر من ترقية نفسه لأدمن
    role = (SELECT role FROM users WHERE id = get_current_user_id())
    OR get_user_role() = 'ADMIN'
  );

-- الأدمن بس يعدل roles
DROP POLICY IF EXISTS "users_admin_update" ON users;
CREATE POLICY "users_admin_update" ON users
  FOR UPDATE USING (get_user_role() = 'ADMIN');

-- =============================================================
-- جدول couriers
-- =============================================================
DROP POLICY IF EXISTS "couriers_select" ON couriers;
CREATE POLICY "couriers_select" ON couriers
  FOR SELECT USING (
    user_id = get_current_user_id()
    OR get_user_role() = 'ADMIN'
    -- العملاء يشوفوا بيانات المندوب لما يكون على أوردرهم
    OR id IN (
      SELECT courier_id FROM orders
      WHERE client_id = get_current_user_id()
        AND status IN ('ACCEPTED', 'PICKED_UP')
    )
  );

DROP POLICY IF EXISTS "couriers_insert_own" ON couriers;
CREATE POLICY "couriers_insert_own" ON couriers
  FOR INSERT WITH CHECK (user_id = get_current_user_id());

DROP POLICY IF EXISTS "couriers_update_own" ON couriers;
CREATE POLICY "couriers_update_own" ON couriers
  FOR UPDATE USING (
    user_id = get_current_user_id()
    OR get_user_role() = 'ADMIN'
  );

-- =============================================================
-- جدول customers
-- =============================================================
DROP POLICY IF EXISTS "customers_select_own" ON customers;
CREATE POLICY "customers_select_own" ON customers
  FOR SELECT USING (
    user_id = get_current_user_id()
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "customers_insert_own" ON customers;
CREATE POLICY "customers_insert_own" ON customers
  FOR INSERT WITH CHECK (user_id = get_current_user_id());

DROP POLICY IF EXISTS "customers_update_own" ON customers;
CREATE POLICY "customers_update_own" ON customers
  FOR UPDATE USING (user_id = get_current_user_id());

-- =============================================================
-- جدول addresses
-- =============================================================
DROP POLICY IF EXISTS "addresses_select_own" ON addresses;
CREATE POLICY "addresses_select_own" ON addresses
  FOR SELECT USING (
    customer_id IN (
      SELECT id FROM customers WHERE user_id = get_current_user_id()
    )
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "addresses_insert_own" ON addresses;
CREATE POLICY "addresses_insert_own" ON addresses
  FOR INSERT WITH CHECK (
    customer_id IN (
      SELECT id FROM customers WHERE user_id = get_current_user_id()
    )
  );

DROP POLICY IF EXISTS "addresses_update_own" ON addresses;
CREATE POLICY "addresses_update_own" ON addresses
  FOR UPDATE USING (
    customer_id IN (
      SELECT id FROM customers WHERE user_id = get_current_user_id()
    )
  );

DROP POLICY IF EXISTS "addresses_delete_own" ON addresses;
CREATE POLICY "addresses_delete_own" ON addresses
  FOR DELETE USING (
    customer_id IN (
      SELECT id FROM customers WHERE user_id = get_current_user_id()
    )
  );

-- =============================================================
-- جدول orders - القلب النووي للأمان
-- =============================================================

-- العميل يشوف أوردراته بس
-- المندوب يشوف: pending + أوردراته المقبولة
-- الأدمن يشوف الكل
DROP POLICY IF EXISTS "orders_select" ON orders;
CREATE POLICY "orders_select" ON orders
  FOR SELECT USING (
    -- العميل يشوف أوردراته
    client_id = get_current_user_id()
    -- المندوب يشوف الـ pending والأوردرات بتاعته
    OR (
      get_user_role() = 'COURIER'
      AND (
        status = 'PENDING'
        OR courier_id = get_current_courier_id()
      )
    )
    -- الأدمن يشوف الكل
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "orders_insert_client" ON orders;
CREATE POLICY "orders_insert_client" ON orders
  FOR INSERT WITH CHECK (
    client_id = get_current_user_id()
    AND get_user_role() = 'CLIENT'
  );

-- العميل يلغي أوردره (PENDING بس)، المندوب يحدث status أوردراته، الأدمن بالكل
DROP POLICY IF EXISTS "orders_update" ON orders;
CREATE POLICY "orders_update" ON orders
  FOR UPDATE USING (
    -- العميل يلغي أوردره لو لسه PENDING
    (client_id = get_current_user_id() AND status = 'PENDING')
    -- المندوب يعدل أوردراته هو بس
    OR (courier_id = get_current_courier_id() AND get_user_role() = 'COURIER')
    OR get_user_role() = 'ADMIN'
  );

-- =============================================================
-- جدول order_items
-- =============================================================
DROP POLICY IF EXISTS "order_items_select" ON order_items;
CREATE POLICY "order_items_select" ON order_items
  FOR SELECT USING (
    order_id IN (
      SELECT id FROM orders WHERE
        client_id = get_current_user_id()
        OR courier_id = get_current_courier_id()
    )
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "order_items_insert" ON order_items;
CREATE POLICY "order_items_insert" ON order_items
  FOR INSERT WITH CHECK (
    order_id IN (
      SELECT id FROM orders WHERE client_id = get_current_user_id()
    )
  );

-- منع حذف items بعد إنشاء الأوردر (الأدمن بس)
DROP POLICY IF EXISTS "order_items_delete_admin" ON order_items;
CREATE POLICY "order_items_delete_admin" ON order_items
  FOR DELETE USING (get_user_role() = 'ADMIN');

-- =============================================================
-- جدول admin_pricing - الأسعار
-- =============================================================
-- الكل يقرأ، الأدمن بس يعدل
DROP POLICY IF EXISTS "pricing_select_all" ON admin_pricing;
CREATE POLICY "pricing_select_all" ON admin_pricing
  FOR SELECT USING (true);

DROP POLICY IF EXISTS "pricing_admin_write" ON admin_pricing;
CREATE POLICY "pricing_admin_write" ON admin_pricing
  FOR ALL USING (get_user_role() = 'ADMIN');

-- =============================================================
-- جدول ad_offers - العروض
-- =============================================================
DROP POLICY IF EXISTS "ads_select_active" ON ad_offers;
CREATE POLICY "ads_select_active" ON ad_offers
  FOR SELECT USING (
    (is_active = true AND end_date > NOW())
    OR get_user_role() = 'ADMIN'
  );

DROP POLICY IF EXISTS "ads_admin_write" ON ad_offers;
CREATE POLICY "ads_admin_write" ON ad_offers
  FOR ALL USING (get_user_role() = 'ADMIN');

-- =============================================================
-- جدول courier_ratings - التقييمات
-- =============================================================
DROP POLICY IF EXISTS "ratings_select" ON courier_ratings;
CREATE POLICY "ratings_select" ON courier_ratings
  FOR SELECT USING (
    courier_id = get_current_courier_id()
    OR get_user_role() = 'ADMIN'
    -- العميل يشوف تقييماته هو
    OR order_id IN (
      SELECT id FROM orders WHERE client_id = get_current_user_id()
    )
  );

DROP POLICY IF EXISTS "ratings_insert_client" ON courier_ratings;
CREATE POLICY "ratings_insert_client" ON courier_ratings
  FOR INSERT WITH CHECK (
    get_user_role() = 'CLIENT'
    AND order_id IN (
      SELECT id FROM orders WHERE client_id = get_current_user_id()
        AND status = 'DELIVERED'
        AND courier_id IS NOT NULL
    )
  );

-- منع تعديل/حذف التقييمات بعد إضافتها
-- (عشان مينفعش حد يغير تقييمه بعد كده)

-- =============================================================
-- Indexes لتحسين الأداء
-- =============================================================
CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_client_id ON orders(client_id);
CREATE INDEX IF NOT EXISTS idx_orders_courier_id ON orders(courier_id);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON orders(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_couriers_user_id ON couriers(user_id);
CREATE INDEX IF NOT EXISTS idx_couriers_status ON couriers(status);
CREATE INDEX IF NOT EXISTS idx_ratings_courier_id ON courier_ratings(courier_id);
CREATE INDEX IF NOT EXISTS idx_ads_active_date ON ad_offers(is_active, end_date);

-- Unique Constraints
CREATE UNIQUE INDEX IF NOT EXISTS couriers_phone_unique ON couriers(phone);
CREATE UNIQUE INDEX IF NOT EXISTS users_phone_unique ON users(phone);

-- =============================================================
-- Function: قبول الأوردر بـ Atomic Transaction (منع Race Condition)
-- SELECT FOR UPDATE NOWAIT = لو الصف محجوز من transaction تانية، بيرجع خطأ فوراً
-- =============================================================
CREATE OR REPLACE FUNCTION accept_order(
  p_order_id TEXT,
  p_courier_id TEXT
)
RETURNS JSON AS $$
DECLARE
  v_order orders%ROWTYPE;
  v_result JSON;
BEGIN
  -- SELECT FOR UPDATE NOWAIT يقفل الصف عشان محدش يقدر ياخده في نفس الوقت
  SELECT * INTO v_order
  FROM orders
  WHERE id = p_order_id
  FOR UPDATE NOWAIT;

  -- لو الأوردر مش موجود
  IF NOT FOUND THEN
    v_result := json_build_object(
      'success', false,
      'message', 'الأوردر مش موجود'
    );
    RETURN v_result;
  END IF;

  -- لو الأوردر مش pending، يبعت رسالة خطأ
  IF v_order.status != 'PENDING' THEN
    v_result := json_build_object(
      'success', false,
      'message', 'الأوردر اتحجز من مندوب تاني'
    );
    RETURN v_result;
  END IF;

  -- تحديث الأوردر لـ ACCEPTED
  UPDATE orders
  SET
    status = 'ACCEPTED',
    courier_id = p_courier_id,
    accepted_at = NOW(),
    updated_at = NOW()
  WHERE id = p_order_id;

  v_result := json_build_object(
    'success', true,
    'message', 'تم قبول الأوردر بنجاح',
    'order_id', p_order_id,
    'courier_id', p_courier_id
  );

  RETURN v_result;

EXCEPTION
  WHEN lock_not_available THEN
    v_result := json_build_object(
      'success', false,
      'message', 'الأوردر بيتحجز دلوقتي، جرب تاني'
    );
    RETURN v_result;
  WHEN OTHERS THEN
    v_result := json_build_object(
      'success', false,
      'message', 'خطأ غير متوقع'
    );
    RETURN v_result;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- امنح صلاحية تشغيل الـ function للـ service role فقط
REVOKE ALL ON FUNCTION accept_order(TEXT, TEXT) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION accept_order(TEXT, TEXT) TO service_role;

-- =============================================================
-- Function: تحديث متوسط تقييم المندوب تلقائياً (Trigger)
-- =============================================================
CREATE OR REPLACE FUNCTION update_courier_avg_rating()
RETURNS TRIGGER AS $$
BEGIN
  UPDATE couriers
  SET rating = (
    SELECT ROUND(AVG(rating)::NUMERIC, 1)
    FROM courier_ratings
    WHERE courier_id = NEW.courier_id
  )
  WHERE id = NEW.courier_id;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- إنشاء الـ trigger
DROP TRIGGER IF EXISTS update_courier_rating_on_insert ON courier_ratings;
CREATE TRIGGER update_courier_rating_on_insert
  AFTER INSERT ON courier_ratings
  FOR EACH ROW
  EXECUTE FUNCTION update_courier_avg_rating();

